def _safe_console(value) -> str:
    return str(value).encode("ascii", "backslashreplace").decode("ascii")


def _flux2_klein_has_645_sui_drift(text: str) -> bool:
    scan = str(text or "")
    return bool(
        re.search(r"\b645\s*(?:AD|CE|year)?\b", scan, re.IGNORECASE)
        and re.search(
            r"\b(?:612\s*(?:AD|CE|year)?|Sui-Goguryeo|Goguryeo-Sui|Sui\s+soldiers?|"
            r"Emperor\s+Yang\s+of\s+Sui|Sui\s+Yangdi|Yangdi|Salsu)\b|"
            r"수\s*양제|수나라|살수",
            scan,
            re.IGNORECASE,
        )
    )


def _flux2_klein_prepare_source_prompt_text(prompt: str) -> str:
    text = (prompt or "").strip() or "an image"
    if "Year/period:" not in text and "Scene:" not in text:
        return text
    if not _flux2_klein_has_645_sui_drift(text):
        return text
    try:
        normalized = normalize_cut_image_prompt(text)
    except Exception:
        return text
    return (normalized or text).strip() or text


def _flux2_klein_is_tang_645_liaodong_context(text: str) -> bool:
    scan = str(text or "")
    return bool(
        re.search(r"\b645\s*(?:AD|CE|year)?\b", scan, re.IGNORECASE)
        and re.search(
            r"\b(?:Tang|Taizong|Li\s+Shimin|Liaodong|Yodong|Ansi|Anshi)\b|"
            r"당\s*태종|당나라|이세민|요동|안시",
            scan,
            re.IGNORECASE,
        )
    )


def _flux2_klein_historical_visual_context_source(prompt: str) -> str:
    text = str(prompt or "")
    match = re.search(
        r"Historical\s+visual\s+context\s*:\s*(.*?)(?=\s+\|\|\s+|$)",
        text,
        flags=re.IGNORECASE | re.DOTALL,
    )
    if not match:
        return text
    return match.group(1).strip(" ;,") or text


def _pad_image_to_canvas(path: str, width: int, height: int) -> None:
    from PIL import Image

    image_path = Path(path)
    with Image.open(image_path) as src:
        img = src.convert("RGBA")
        canvas_w = int(width)
        canvas_h = int(height)
        scale = max(canvas_w / img.width, canvas_h / img.height)
        canvas = img.resize(
            (max(1, int(img.width * scale)), max(1, int(img.height * scale))),
            Image.Resampling.LANCZOS,
        )
        left = max(0, (canvas.width - canvas_w) // 2)
        top = max(0, int((canvas.height - canvas_h) * 0.28))
        canvas = canvas.crop((left, top, left + canvas_w, top + canvas_h))
        canvas.convert("RGB").save(image_path)


