def _append_unique_negative(base: str, extra: str) -> str:
    seen: set[str] = set()
    out: list[str] = []
    for part in (base, extra):
        for token in [x.strip() for x in (part or "").split(",") if x.strip()]:
            key = token.lower()
            if key not in seen:
                seen.add(key)
                out.append(token)
    return ", ".join(out)


def _strip_local_v1_positive_only_prompt(prompt: str) -> str:
    cleaned = prompt or ""
    legacy_negative_lock_patterns = (
        r"\s*\|\|\s*HARD\s+HISTORICAL\s+MATERIAL\s+CULTURE\s+LOCK\b.*?(?=\s*\|\|\s*[A-Z★]|$)",
        r"\s*\|\|\s*★\s*HARD\s+CONSTRAINT\s+—\s+ABSOLUTELY\s+NO\s+TEXT.*?(?=\s*\|\|\s*[A-Z★]|$)",
        r"\s*\|\|\s*★\s*HARD\s+CONSTRAINT\s+—\s+ABSOLUTELY\s+NO\s+MAPS.*?(?=\s*\|\|\s*[A-Z★]|$)",
    )
    for pattern in legacy_negative_lock_patterns:
        cleaned = re.sub(pattern, "", cleaned, flags=re.IGNORECASE | re.DOTALL)
    cleaned = re.sub(
        r"\s*Apply\s+this\s+as\s+rendering\s+style\s+only\s+while\s+preserving.*?(?=\s+\|\||$)",
        " ",
        cleaned,
        flags=re.IGNORECASE | re.DOTALL,
    )
    cleaned = re.sub(
        r",?\s*\bno\s+(?:readable\s+)?(?:text|labels|letters|numbers|captions|logo|watermark|exterior\s+landscape\s+view)\b",
        "",
        cleaned,
        flags=re.IGNORECASE,
    )
    cleaned = re.sub(r"\s{2,}", " ", cleaned).strip(" ,")
    return cleaned or (prompt or "").strip() or "an image"


