def _local_rewrite_blank_record_scene(scene: str) -> str:
    out = scene or ""
    replacements = (
        (
            r"\bA\s+steward\s+checks\s+a\s+blank\s+roster\b",
            "A steward checks a small closed cord-tied obligation bundle and wooden tally tags",
        ),
        (
            r"\bblank\s+rosters?\b",
            "small closed cord-tied bundles and wooden tally tags",
        ),
        (
            r"\bretainer\s+rosters?\b|\brosters?\b|\bregisters?\b|\bledgers?\b|\brecords?\b|\bdocuments?\b",
            "small closed cord-tied bundles",
        ),
        (
            r"\bblank\s+paper\b|\bpaper\b|\bpage\b|\bpages\b",
            "folded edge-on bundle",
        ),
        (
            r"\btied\s+blank\s+orders?\b|\bblank\s+orders?\b|\bduty\s+assignments?\b|\bassignments?\b|\borders?\b",
            "small tied roll cylinders and plain wooden tally tags",
        ),
    )
    for pattern, replacement in replacements:
        out = re.sub(pattern, replacement, out, flags=re.IGNORECASE)
    return re.sub(r"\s{2,}", " ", out).strip()


