def _local_normalize_historical_tally_scene_language(prompt: str) -> str:
    p = prompt or ""
    scene = _local_scene_excerpt(p)
    if not scene or not re.search(
        r"\b(scribe|record|records|register|roster|tax\s+register|ledger|"
        r"tally|tallies|tally\s+board|tally\s+mat|survey\s+results?|"
        r"land\s+capacity|military\s+obligation|account|accounting)\b|"
        r"(서기|기록|장부|명부|호적|조사|측량|군역|세금|계수)",
        scene,
        re.IGNORECASE,
    ):
        return p
    replacements = (
        (
            r"\bA\s+scribe\s+marks\s+a\s+blank\s+tally\s+board\b",
            "A scribe arranges plain notched wooden tally sticks, cord knots, and pebble counters on a rough blank counting mat",
        ),
        (
            r"\bmarks\s+a\s+blank\s+tally\s+board\b",
            "arranges plain notched wooden tally sticks, cord knots, and pebble counters on a rough blank counting mat",
        ),
        (
            r"\bblank\s+tally\s+boards?\b",
            "plain notched wooden tally sticks, cord knots, and pebble counters",
        ),
        (
            r"\btally\s+boards?\b",
            "plain notched wooden tally sticks, cord knots, and pebble counters",
        ),
        (
            r"\bfield-side\s+writing\s+mat\b",
            "field-side rough counting mat with notched wooden tally sticks, cord knots, and pebble counters",
        ),
        (
            r"\bscribe\s+recording\s+survey\s+results\b",
            "scribe arranging physical tally counters for survey results",
        ),
    )
    for pattern, replacement in replacements:
        p = re.sub(pattern, replacement, p, flags=re.IGNORECASE)
    return re.sub(r"\s{2,}", " ", p).strip()


def _local_is_achaemenid_egyptian_context(prompt: str) -> bool:
    p = prompt or ""
    if (
        "period-local achaemenid persian and egyptian material culture lock" in p.lower()
        or "achaemenid persian and egyptian armed group composition" in p.lower()
        or "525 bc achaemenid persian, pelusium" in p.lower()
    ):
        return True
    if _local_is_modern_context(p):
        return False
    year = _local_prompt_field(p, "Year/period")
    place = _local_prompt_field(p, "Exact place")
    culture = _local_prompt_field(p, "Culture scope")
    text = " ".join(part for part in (year, place, culture, p) if part)
    has_region = bool(
        re.search(
            r"\b(Achaemenid|Persian|Persia|Cambyses|Pelusium|Nile\s+Delta|"
            r"Egypt|Egyptian|Pharaoh|Psamtik|Amasis|Phanes)\b|"
            r"(페르시아|이집트|캄비세스|펠루시움|파라오)",
            text,
            re.IGNORECASE,
        )
    )
    has_period = bool(
        re.search(
            r"\b(?:525|52\d|5\d{2})\s*(?:BCE|BC)\b|"
            r"\b(?:BCE|BC|ancient|Late\s+Period)\b|기원전",
            text,
            re.IGNORECASE,
        )
    )
    return bool(has_region and has_period)


def _local_scene_is_explicit_ancient_egypt_context(prompt: str) -> bool:
    p = prompt or ""
    if _local_is_modern_context(p):
        return False
    year = _local_prompt_field(p, "Year/period")
    place = _local_prompt_field(p, "Exact place")
    culture = _local_prompt_field(p, "Culture scope")
    subject = _local_prompt_field(p, "Main subject")
    scene = _local_scene_excerpt(p, limit=700)
    field_text = " ".join(part for part in (year, place, culture, subject, scene) if part)
    scan = field_text or p
    scan = re.sub(
        r"\b(?:no|not|without|avoid|forbidden|exclude)\b[^.;|]{0,140}"
        r"\b(?:Egypt|Egyptian|Pharaoh|Nile|Menes|Narmer|crook|flail|hippo|hippopotamus)\b[^.;|]*",
        " ",
        scan,
        flags=re.IGNORECASE,
    )
    return bool(
        re.search(
            r"\b(?:ancient\s+Egypt|ancient\s+Egyptian|Egyptian\s+Pharaoh|"
            r"Egyptian\s+scribe|Pharaoh|Menes|Narmer|Nile|Upper\s+Egypt|"
            r"Lower\s+Egypt|double\s+crown|pschent|crook\s+and\s+flail|"
            r"pharaoh'?s\s+mask|papyrus\s+reeds?|reed\s+banks?|pyramids?|"
            r"Great\s+Sphinx|Sphinx|sacred\s+bull|sun\s+disk|hippopotamus|hippo)\b|"
            r"(?:고대\s*이집트|파라오|나일강)",
            scan,
            re.IGNORECASE,
        )
    )


