def _local_is_late_medieval_western_europe_context(prompt: str) -> bool:
    p = prompt or ""
    if _local_is_modern_context(p):
        return False
    year = _local_prompt_field(p, "Year/period")
    place = _local_prompt_field(p, "Exact place")
    culture = _local_prompt_field(p, "Culture scope")
    scene = _local_scene_excerpt(p, limit=500)
    field_text = " ".join(part for part in (year, place, culture, scene) if part)
    text = field_text or p
    has_region = bool(
        re.search(
            r"\b(?:Europe|European|Western\s+Europe|Latin\s+West|France|French|"
            r"Navarre|Navarrese|Pamplona|Iberia|Iberian|Spain|Spanish|Castile|"
            r"Castilian|Aragon|Aragonese|England|English|Burgundy|Burgundian|"
            r"Gothic\s+castle|medieval\s+castle|medieval\s+king)\b",
            text,
            re.IGNORECASE,
        )
    )
    has_period = bool(
        re.search(
            r"\b(?:12[5-9]\d|13\d{2}|14[0-4]\d)\s*(?:AD|CE)?\b|"
            r"\b(?:13th|14th|early\s+15th|late\s+medieval)\s+century\b|"
            r"\bmedieval\b",
            text,
            re.IGNORECASE,
        )
    )
    return bool(has_region and has_period)


def _local_is_early_modern_europe_context(prompt: str) -> bool:
    p = prompt or ""
    if _local_is_modern_context(p):
        return False
    year = _local_prompt_field(p, "Year/period")
    place = _local_prompt_field(p, "Exact place")
    culture = _local_prompt_field(p, "Culture scope")
    scene = _local_scene_excerpt(p, limit=500)
    if re.search(
        r"\b(?:ancient|classical|archaic|hellenistic|BCE|BC|Aeschylus)\b",
        scene,
        re.IGNORECASE,
    ) and re.search(
        r"\b(?:Greek|Greece|Hellenic|Hellenistic|Ionian|Ionia|Aeschylus|amphitheater|theater|theatre)\b",
        scene,
        re.IGNORECASE,
    ):
        return False
    field_text = " ".join(part for part in (year, place, culture, scene) if part)
    text = field_text or p
    has_region = bool(
        re.search(
            r"\b(?:Europe|European|Holy\s+Roman\s+Empire|Prague|Bohemia|"
            r"Czech|German|Germany|Danish|Denmark|Habsburg|Renaissance|"
            r"Tycho|Brahe|Kepler|astronomer|astronomy)\b",
            text,
            re.IGNORECASE,
        )
    )
    has_period = bool(
        re.search(
            r"\b(?:14\d{2}|15\d{2}|16\d{2}|17\d{2})\s*(?:AD|CE)?\b|"
            r"\b(?:15th|16th|17th)\s+century\b|"
            r"\b(?:Renaissance|early[-\s]*modern)\b",
            text,
            re.IGNORECASE,
        )
    )
    return bool(has_region and has_period)


