def _local_scene_has_named_character_action(scene: str) -> bool:
    text = scene or ""
    if not text:
        return False
    if _LOCAL_EXPLICIT_HUMAN_OR_COMBATANT_SCENE_RE.search(text):
        return True
    for match in _LOCAL_PROPER_NAME_SCENE_RE.finditer(text):
        name = re.sub(r"\s+", " ", match.group(0)).strip().lower()
        if (
            name not in _LOCAL_PROPER_NAME_NON_PERSON_WORDS
            and (
                re.search(
                    r"\b(close[-\s]*up|portrait|face|eyes?|gaze|expression)\b",
                    text[max(0, match.start() - 90) : match.start()],
                    re.IGNORECASE,
                )
                or _LOCAL_CHARACTER_ACTION_SCENE_RE.search(text[match.end() : match.end() + 140])
            )
        ):
            return True
    return False

