def _local_scene_requests_exact_symbolic_scene(prompt: str) -> bool:
    scene = _local_scene_excerpt(prompt)
    if not scene:
        return False
    if (
        _local_scene_requests_empty_outdoor_field(prompt)
        or _local_scene_requests_split_screen_contrast(prompt)
        or _local_scene_requests_opposed_flags_or_banners(prompt)
        or _local_scene_requests_wealth_visible_action(prompt)
        or _local_scene_requests_stone_pillar_erection(prompt)
        or _local_scene_requests_visible_handheld_weapon(prompt)
        or _local_scene_requests_labor_camp(prompt)
        or _local_scene_requests_handholding_group(prompt)
        or _local_scene_requests_family_control_touch(prompt)
        or _local_scene_requests_tally_calculation_group(prompt)
    ):
        return False
    return bool(
        re.search(
            r"\b(chessboard|boomerang|deadly\s+arrow|arrow\s+piercing|distant\s+target|"
            r"blood\s+and\s+sweat|foreign\s+army\s+crossing|political\s+factions|"
            r"factions\s+glaring|torn\s+wedding\s+garment|handing\s+over\s+a\s+map|"
            r"throne\s+sitting\s+atop|broken\s+shields|abacus|calculator|"
            r"monstrous\s+shadow|wedding\s+ceremony|face\s+morphing|greedy\s+monster|"
            r"poisoned\s+cup|torn\s+family\s+portrait|dark\s+mirror\s+reflecting|"
            r"brutal,\s+bloody\s+reality|brutal\s+visible\s+only\s+as\s+distorted\s+reflection|"
            r"bloody\s+brush|bamboo\s+scroll|"
            r"borders\s+drawn\s+in\s+fire|executing|severed\s+head|clenched\s+fist|"
            r"lone\s+survivor|pile\s+of\s+bodies|wolf\s+pack|tiger\s+transforming|"
            r"small\s+cat|illusion\b.*\bshattering|cold,\s+unblinking\s+eye|"
            r"unblinking\s+eye|burning\s+fire|scalpel\s+slicing)\b",
            scene,
            re.IGNORECASE | re.DOTALL,
        )
    )


def _local_symbolic_scene_required_evidence(scene: str) -> str:
    s = scene or ""
    checks: tuple[tuple[str, str], ...] = (
        (r"\bchessboard\b", "Show one low period game board or chessboard-like tactical board with toppled pieces and visible blood stains; no wall sign, no door, no room facade."),
        (r"\bboomerang\b", "Show the boomerang-shaped weapon/object itself flying back through open air with blood on its edge and motion streaks; no person-at-door replacement."),
        (r"\bdeadly\s+arrow|arrow\s+piercing|target\b", "Show the arrow actively piercing the distant target, with the shaft embedded in the target and impact splinters visible."),
        (r"\bblood\s+and\s+sweat\b", "Use a close ground evidence frame: dry cracked earth, red blood drops, sweat droplets, dust, and hard light; no doorway or wall."),
        (r"\bforeign\s+army\s+crossing\b", "Use a wide dark border-crossing scene with multiple armed soldiers or riders moving across a road, riverbank, ridge, or frontier line at night."),
        (r"\bfactions?\b.*\bglaring|political\s+factions", "Show two hostile political groups facing each other across a room, courtyard, or table with hard eye-lines and tense body angles."),
        (r"\btorn\s+wedding\s+garment\b", "Show the torn wedding garment as the dominant cloth evidence, visibly ripped and blood-stained, laid on a surface or hanging empty."),
        (r"\bhanding\s+over\s+a\s+map\b", "Show the son and the enemy general in the same frame, one hand passing a blank physical map bundle or unmarked map surface to the other."),
        (r"\bthrone\s+sitting\s+atop|broken\s+shields", "Show the throne clearly sitting on a mound of broken shields; the throne and shield pile are the first readable subject."),
        (r"\babacus|calculator\b", "Show a period counting frame or abacus-like counter with rods or beads and blood dripping on it; no hanging door hardware."),
        (r"\bmonstrous\s+shadow|wedding\s+ceremony", "Show a wedding ceremony group under a looming monstrous shadow cast across the wall or ground."),
        (r"\btiger'?s?\s+face\b.*\bmorph|morphing\s+into\s+a\s+rugged\s+warrior'?s?\s+face|tiger\b.*\bwarrior'?s?\s+face", "Show one close split face only: one side is a natural tiger face with fur, stripes, whiskers, and feline eye; the other side is a rugged human warrior face with skin, brow, scars or beard, and human eye. The morph boundary stays inside the same close face. No full tiger body, no tiger torso, no animal wearing robe, no animal wearing human clothing, no doorway portrait."),
        (r"\bface\s+morphing|greedy\s+monster", "Show one face visibly split or transforming into a greedy monster face, with the morph boundary readable inside the face."),
        (r"\bpoisoned\s+cup\b", "Show the poisoned cup on a royal table as the dominant object, with dark liquid, spill, or poison trace; no empty veranda."),
        (r"\btorn\s+family\s+portrait\b", "Show a physical family portrait surface with a large jagged tear line cutting through the figures, two separated ripped paper halves, curled torn edges, and visible damage across the faces; keep it as an object surface, not a live group photo or intact framed portrait."),
        (r"\bdark\s+mirror\s+reflecting|brutal,\s+bloody\s+reality|brutal\s+visible\s+only\s+as\s+distorted\s+reflection", "Show the dark mirror as the dominant object with a cracked reflective surface and a brutal bloody reality visible only as distorted reflection inside the mirror."),
        (r"\bbloody\s+brush|bamboo\s+scroll", "Show a brush dragging blood across a bamboo scroll or blank scroll surface; no readable characters, no glyph rows."),
        (r"\bborders\s+drawn\s+in\s+fire", "Show a steep top-down tabletop or floor crop of an unlabelled East Asia map-like evidence surface with borders indicated by fire lines, glowing cords, burning edges, or glowing cracks; no architecture, no doorway, no gate, no text labels."),
        (r"\bexecuting\b", "Show the execution action: soldiers restrain or strike a foreign official in the dark, with clear action posture and no static lineup."),
        (r"\bsevered\s+head\b", "Show the severed head rolling on the dirt floor as the first readable subject, with dust and blood trail; no intact lying body replacing it."),
        (r"\bclenched\s+fist\b", "Show one clenched fist trembling with rage as the dominant body-detail action, knuckles tight, tendons and sleeve tension visible, no face, no head, no portrait, no clasped-prayer hands."),
        (r"\blone\s+survivor|pile\s+of\s+bodies", "Show the lone survivor standing above or beside a visible pile of bodies, not an empty standing portrait."),
        (r"\bwolf\s+pack\b", "Show multiple wolves circling through snow with clear four-legged anatomy and pack spacing; no gate or building replacement."),
        (r"\btiger\s+transforming|small\s+cat\b", "Show a transformation sequence or split morph from a small cat into a fierce tiger in the same frame, not a lone tiger by a door."),
        (r"\billusion\b.*\bshattering", "Show a peaceful kingdom image breaking into sharp glass-like shards, with fractured edges and dark reality behind it."),
        (r"\bunblinking\s+eye|burning\s+fire", "Show a cold unblinking eye in close detail with a burning fire reflected in the iris; no door or room replacement."),
        (r"\bscalpel\s+slicing", "Show a close object-evidence frame of a small scalpel blade cutting through a flat romantic painting surface, with sliced canvas or paper fibers visible; no duel, no two people fighting, no sword scene, no readable writing on the painting or support."),
    )
    for pattern, clause in checks:
        if re.search(pattern, s, re.IGNORECASE | re.DOTALL):
            return clause
    return "Preserve every concrete noun and action from the Scene as visible evidence in one frame; do not replace it with a generic doorway, gate, wall, or portrait."


def _local_scene_is_stealth_sleeping_guard_story(prompt: str) -> bool:
    scene = _local_scene_excerpt(prompt)
    if not scene:
        return False
    has_stealth_motion = bool(
        re.search(
            r"\b(sneak|sneaks|sneaking|slip|slips|slipping|creep|creeps|creeping|"
            r"escape|escapes|escaping|flee|flees|fleeing|away|path)\b",
            scene,
            re.IGNORECASE,
        )
    )
    has_inactive_guard = bool(
        re.search(r"\b(sleeping|asleep|drunk|drunken|unconscious|drowsy)\b", scene, re.IGNORECASE)
        and re.search(r"\b(guard|guards|watchman|watchmen|soldier|soldiers)\b", scene, re.IGNORECASE)
    )
    return bool(has_stealth_motion and has_inactive_guard)


def _local_scene_requests_achaemenid_egyptian_armed_group(prompt: str) -> bool:
    if not _local_is_achaemenid_egyptian_context(prompt):
        return False
    if _local_scene_is_stealth_sleeping_guard_story(prompt):
        return False
    scene = _local_scene_excerpt(prompt)
    return bool(
        _local_scene_requests_armed_figures(prompt)
        and (
            _local_scene_requests_group(prompt)
            or re.search(
                r"\b(soldiers|guards|fighters|archers|armies|army|formation|cavalry|"
                r"militia|spearmen|swordsmen|troops|defenders|attackers|"
                r"battle\s*line|march|marching|advance|advancing|charge|charging|"
                r"clash|armed group|armed crowd)\b|"
                r"(군인|병사|호위|전사들|무사들|궁수들|군대|대열|기병|행군|진격|돌격)",
                scene,
                re.IGNORECASE,
            )
        )
    )


def _local_scene_is_animal_focused_without_people(prompt: str) -> bool:
    scene = _local_scene_excerpt(prompt)
    return bool(
        scene
        and _LOCAL_ANIMAL_FOCUS_SCENE_RE.search(scene)
        and not _LOCAL_EXPLICIT_HUMAN_OR_COMBATANT_SCENE_RE.search(scene)
    )


