def _local_scene_requests_exactly_one_living_person(prompt: str) -> bool:
    if _local_scene_requests_generic_object_evidence(prompt):
        return False
    if _local_scene_is_inanimate_statue_object_without_living_people(prompt):
        return False
    scene = _local_scene_excerpt(prompt, limit=700)
    if not scene or _local_scene_requests_group(prompt):
        return False
    if re.search(
        r"\b(two|three|four|five|six|several|many|group|crowd|people|"
        r"men|women|actors?|performers?|soldiers|guards|officials|"
        r"companions|assistants|council|assembly|procession|audience)\b",
        scene,
        re.IGNORECASE,
    ):
        return False
    return bool(
        re.search(
            r"\b(?:a|an|one|single)\s+(?:adult\s+|aging\s+|old\s+|young\s+|"
            r"arrogant\s+|terrified\s+|frightened\s+|wounded\s+|angry\s+|"
            r"desperate\s+|historical\s+|ancient\s+|medieval\s+|royal\s+)?"
            r"(?:man|woman|person|figure|ruler|king|queen|emperor|empress|"
            r"prince|princess|priest|priestess|monk|scholar|writer|artist|"
            r"messenger|guard|soldier|warrior|runner|traveler|official|"
            r"nobleman|noblewoman|commander)\b"
            r"|\b(Aeschylus|Tycho\s+Brahe|Kepler|Johannes\s+Kepler|"
            r"Ashikaga\s+Takauji|Nitta\s+Yoshisada|Go-?Daigo|Jumong|"
            r"Yeontabal|Cambyses(?:\s+II)?)\b",
            scene,
            re.IGNORECASE,
        )
    )


