def _local_scene_requests_map(prompt: str) -> bool:
    scene = _local_scene_excerpt(prompt)
    scene = re.sub(
        r"\b(?:no|without|avoid|forbid(?:den)?|exclude|not|never)\s+"
        r"(?:a\s+|an\s+|the\s+)?(?:world\s+|paper\s+|written\s+|readable\s+|labeled\s+)?maps?\b",
        " ",
        scene,
        flags=re.IGNORECASE,
    )
    scene = re.sub(
        r"\bmaps?\s+(?:labels?|text|writing|characters?|names?)\b",
        " ",
        scene,
        flags=re.IGNORECASE,
    )
    return bool(
        re.search(
            r"\b(?:maps?|campaign\s+map|strategic\s+map|physical\s+map|"
            r"tactile\s+campaign\s+board|tactile\s+strategy\s+board|"
            r"tactile\s+marker\s+layout|horizontal\s+tactile\s+marker\s+layout|"
            r"tactile\s+land[-\s]+marker\s+layout|"
            r"cloth\s+planning\s+surface|ground-level\s+tabletop\s+surface|"
            r"strategy\s+board|blank-board\s+strategy\s+shot|tabletop\s+map|"
            r"relief\s+terrain\s+board|ground\s+plan|sand[-\s]+marked\s+ground\s+plan|"
            r"ground\s+diagram|field\s+diagram|drawn\s+route\s+lines?)\b|지도",
            scene,
            re.IGNORECASE,
        )
    )


