def _local_map_scene_summary(prompt: str) -> str:
    scene = _local_scene_excerpt(prompt).lower()
    parts: list[str] = ["requested region shown through cord paths, stone clusters, bronze weights, blank zones, and shadow pressure"]
    if "dark" in scene:
        parts.append("dark charcoal wash mood across wide blank board zones")
    if re.search(r"\b(uncontrolled|controlled|control)\b", scene):
        parts.append("control pressure shown by empty blank zones and separated marker groups")
    if re.search(r"\b(route|routes|border|borders|frontier|territory|territories)\b", scene):
        parts.append("routes and borders shown by cord paths, folded cloth strips, and stone clusters")
    return "; ".join(parts)


def _local_scene_requests_armed_figures(prompt: str) -> bool:
    if _local_scene_requests_generic_object_evidence(prompt):
        return False
    p = prompt or ""
    subject_match = re.search(
        r"\bScene\s+subject\s*:\s*(.*?)(?=\.|$)",
        p,
        flags=re.IGNORECASE | re.DOTALL,
    )
    search_text = subject_match.group(1) if subject_match else _local_scene_excerpt(p)
    if _local_scene_is_depicted_people_on_object_without_living_people(prompt):
        return False
    if _local_scene_is_animal_focused_without_people(prompt):
        return False
    if _local_scene_is_stealth_sleeping_guard_story(prompt):
        return False
    if _local_scene_requests_bow_without_arrow_action(prompt):
        return False
    if (
        _local_is_medieval_japanese_context(prompt)
        and not _local_scene_names_specific_weapon(prompt)
        and not _local_scene_requests_medieval_japanese_protective_dress(prompt)
    ):
        return False
    if not _local_scene_names_specific_weapon(prompt):
        has_view_or_arrival = bool(
            re.search(
                r"\b(looking|gazing|watching|staring|standing|arriving|arrives|"
                r"reaching|entering)(?:\s+\w+){0,5}\s+(?:out\s+)?"
                r"(?:over|toward|at|from|into)\b|\boverlook(?:ing)?\b",
                search_text,
                re.IGNORECASE,
            )
        )
        has_landscape_target = bool(
            re.search(
                r"\b(valley|city|skyline|river|field|fields|landscape|"
                r"mountain|mountains|horizon|view|ridge|hill|cliff|"
                r"settlement|village)\b",
                search_text,
                re.IGNORECASE,
            )
        )
        if has_view_or_arrival and has_landscape_target:
            return False
    if (
        _local_scene_has_formal_role_terms(search_text)
        and not _local_scene_names_specific_weapon(prompt)
        and not re.search(
            r"\b(battle|battlefield|combat|clash|charge|charging|attack|attacking|"
            r"fight|fighting|strike|striking|shoot|shooting|aim|aiming|grip|gripping|"
            r"hold|holding|raise|raising)\b|전투|전장|돌격|공격|교전|겨냥|사격|쏘|들고|쥐고",
            search_text,
            re.IGNORECASE,
        )
    ):
        return False
    return bool(
        re.search(
            r"\b(soldier|soldiers|guard|guards|escort|escorts|warrior|warriors|fighter|fighters|"
            r"archer|archers|army|armies|battle|battlefield|combat|clash|formation|"
            r"cavalry|horsemen|horde|troops|defenders|attackers|"
            r"weapon|weapons|armed|spear|spears|sword|swords|tachi|bow|bows|arrow|arrows|"
            r"shoot|shooting|aim|aiming|rifle|rifles|"
            r"gun|guns|firearm|firearms|baton|batons|shield|shields)\b",
            search_text,
            re.IGNORECASE,
        )
    )


