def _local_scene_requests_combat_action(prompt: str) -> bool:
    return bool(
        re.search(
            r"\b(battle|battlefield|combat|clash|charge|charging|attack|attacking|"
            r"fight|fighting|strike|striking|shoot|shooting|aim|aiming|"
            r"ambush|raid|pursuit|duel|skirmish|siege)\b|"
            r"전투|전장|돌격|공격|교전|겨냥|사격|쏘|매복|추격|공성",
            _local_scene_excerpt(prompt),
            re.IGNORECASE,
        )
    )


def _local_scene_requests_medieval_japanese_protective_dress(prompt: str) -> bool:
    has_medieval_japanese_context = bool(
        _local_is_medieval_japanese_context(prompt)
        or "period-local japanese costume and armor lock" in (prompt or "").lower()
        or "period-local japanese martial clothing lock" in (prompt or "").lower()
        or "period-local japanese court and civilian costume lock" in (prompt or "").lower()
    )
    return bool(
        has_medieval_japanese_context
        and (
            _local_scene_explicitly_names_protective_torso_gear(prompt)
            or _local_scene_requests_combat_action(prompt)
        )
    )


def _local_scene_requests_bow_without_arrow_action(prompt: str) -> bool:
    scene = _local_scene_excerpt(prompt)
    has_bow = bool(re.search(r"\b(bow|bows)\b|활", scene, re.IGNORECASE))
    has_arrow_action = bool(
        re.search(
            r"\b(arrow|arrows|shoot|shooting|aim|aiming|target|long-distance)\b|"
            r"화살|사격|쏘|겨냥|백보|100보",
            scene,
            re.IGNORECASE,
        )
    )
    return has_bow and not has_arrow_action


def _local_scene_requests_civilian_work_or_camp(prompt: str) -> bool:
    scene = _local_scene_excerpt(prompt)
    return bool(
        re.search(
            r"\b(camp|refugee|refugees|fugitive|fugitives|settler|settlers|"
            r"worker|workers|farmer|farmers|villager|villagers|migration|"
            r"migrants|household|family|market|kitchen|field work|harvest|"
            r"shelter|shelters)\b|"
            r"(난민|피난민|이주민|농민|일꾼|마을사람|가족|가정|시장|부엌|피난|정착|수확|움막)",
            scene,
            re.IGNORECASE,
        )
        and not _local_scene_requests_armed_figures(prompt)
    )


def _enforce_local_single_closeup_head_prompt(prompt: str) -> str:
    p = prompt or ""
    replacements = (
        (
            r"\bsimple\s+tied\s+hair\s+or\s+cloth\s+headband\b",
            "simple tied hair behind the head",
        ),
        (
            r"\bvisible\s+tied\s+hair\s+and\s+flat\s+cloth\s+headband\s+close\s+to\s+the\s+skull\b",
            "visible natural hairline and simple tied hair behind the head",
        ),
        (
            r"\btied\s+hair,\s*flat\s+cloth\s+band\s+close\s+to\s+the\s+skull\b",
            "simple tied hair behind the head, visible natural hairline",
        ),
        (
            r"\bflat\s+cloth\s+band\s+close\s+to\s+the\s+skull\b",
            "visible natural hairline",
        ),
        (
            r"\bflat\s+cloth\s+headband\s+close\s+to\s+the\s+skull\b",
            "visible natural hairline",
        ),
        (
            r"\bcloth\s+headband\b",
            "natural hairline",
        ),
        (
            r"\bheadband\b",
            "natural hairline",
        ),
        (
            r"\bHeadwear,\s*when\s+the\s+Scene\s+role\s+requires\s+it,\s*forms\s+one\s+compact\s+rounded\s+cap\s+that\s+stays\s+close\s+to\s+the\s+skull\.",
            "The upper head area is natural hairline, tied hair, and continuous forehead skin.",
        ),
        (
            r"\bcompact\s+rounded\s+cap\b",
            "natural tied hair shape",
        ),
        (
            r"\bheadwear\b",
            "natural hairline",
        ),
        (
            r"\bhelmet\b",
            "natural hairline and tied hair",
        ),
    )
    for pattern, replacement in replacements:
        p = re.sub(pattern, replacement, p, flags=re.IGNORECASE)
    if "Bare compact human head for close portraits" not in p:
        p = p.rstrip() + " " + LOCAL_CHARACTER_CLOSEUP_HEAD_PHRASE
    p = re.sub(r"\s{2,}", " ", p).strip()
    return p


def _enforce_local_armed_figure_loadout_prompt(prompt: str) -> str:
    p = prompt or ""
    is_medieval_japanese = _local_is_medieval_japanese_context(p)
    is_achaemenid_egyptian = _local_is_achaemenid_egyptian_context(p)
    is_early_ancient_chinese = _local_is_early_ancient_chinese_context(p)
    is_medieval_central_asian = _local_is_medieval_central_asian_context(p)
    if (
        _local_prompt_is_object_only(p)
        and not _local_scene_requests_group(p)
        and not _local_scene_requests_single_character(p)
    ):
        return re.sub(r"\s{2,}", " ", p).strip()
    replacements: list[tuple[str, str]] = [
        (
            r"\bround\s+wooden\s+shields,\s*bows,\s*short\s+blades\b",
            "one selected primary weapon per person",
        ),
        (
            r"\bbows,\s*short\s+blades\b",
            "one selected primary weapon per person",
        ),
        (
            r"\bbroken\s+round\s+shields,\s*short\s+blades,\s*bows\b",
            "one representative armed person holding one primary weapon",
        ),
        (
            r"\bplain\s+round\s+shield\s+faces,\s*",
            "",
        ),
        (
            r"\bvertical\s+props\s+appear\s+as\s+plain\s+spear\s+shafts\b",
            "vertical props appear only on people whose single weapon is a spear",
        ),
        (
            r"\bhands\s+near\s+short\s+blades\s+at\s+their\s+waists\b",
            "one visible short blade per armed person at the waist",
        ),
    ]
    if is_medieval_japanese:
        replacements.extend(
            [
                (
                    r"\b(?:carrying|holding|gripping|raising|lifting)\s+(?:a\s+)?shields?\b",
                    "holding empty off-hands near belts",
                ),
                (
                    r"\bwith\s+(?:a\s+)?shields?\b",
                    "with empty off-hands",
                ),
                (
                    r"\bshield\s+walls?\b",
                    "close samurai line with empty off-hands",
                ),
                (
                    r"\bshields?\b",
                    "empty off-hands",
                ),
                (
                    r"방패를\s*(?:들고|쥐고|올리고|든|든 채)",
                    "빈 손을 허리 가까이에 두고",
                ),
                (
                    r"방패",
                    "빈 손",
                ),
            ]
        )
    for pattern, replacement in replacements:
        p = re.sub(pattern, replacement, p, flags=re.IGNORECASE)
    if _local_scene_requests_bow_without_arrow_action(p) and "SELECTED PERIOD WEAPON LOCK" not in p:
        p = p.rstrip() + " " + _local_selected_period_weapon_phrase(p)
        return re.sub(r"\s{2,}", " ", p).strip()
    is_achaemenid_armed_group = _local_scene_requests_achaemenid_egyptian_armed_group(p)
    if is_achaemenid_armed_group:
        if "Achaemenid Persian and Egyptian armed group composition" not in p:
            p = p.rstrip() + " " + LOCAL_ACHAEMENID_EGYPTIAN_ARMED_GROUP_PHRASE
        if "ARMED BODY VISIBLE SET LOCK" not in p:
            p = p.rstrip() + " " + LOCAL_ACHAEMENID_EGYPTIAN_ARMED_BODY_VISIBLE_SET_PHRASE
        if _local_scene_requests_armed_figures(p) and "SELECTED PERIOD WEAPON LOCK" not in p:
            p = p.rstrip() + " " + _local_selected_period_weapon_phrase(p)
        return re.sub(r"\s{2,}", " ", p).strip()
    if (
        _local_scene_requests_armed_figures(p)
        and not _local_scene_names_specific_weapon(p)
        and not is_achaemenid_armed_group
        and "ARMED ROLE PORTRAIT CROP LOCK" not in p
    ):
        p = p.rstrip() + " " + LOCAL_ARMED_ROLE_PORTRAIT_CROP_PHRASE
        if "ARMED BODY VISIBLE SET LOCK" not in p:
            p = p.rstrip() + " " + (
                LOCAL_JAPANESE_ARMED_BODY_VISIBLE_SET_PHRASE
                if is_medieval_japanese
                else LOCAL_MEDIEVAL_CENTRAL_ASIAN_ARMED_BODY_VISIBLE_SET_PHRASE
                if is_medieval_central_asian
                else LOCAL_EARLY_ANCIENT_CHINESE_ARMED_BODY_VISIBLE_SET_PHRASE
                if is_early_ancient_chinese
                else LOCAL_ACHAEMENID_EGYPTIAN_ARMED_BODY_VISIBLE_SET_PHRASE
                if is_achaemenid_egyptian
                else LOCAL_ARMED_BODY_VISIBLE_SET_PHRASE
            )
        return re.sub(r"\s{2,}", " ", p).strip()
    if _local_scene_requests_armed_figures(p) and "Each armed person has one simple visible primary weapon only" not in p:
        p = p.rstrip() + " " + LOCAL_ARMED_FIGURE_LOADOUT_PHRASE
    if _local_scene_requests_armed_figures(p) and "ARMED BODY VISIBLE SET LOCK" not in p:
        p = p.rstrip() + " " + (
            LOCAL_JAPANESE_ARMED_BODY_VISIBLE_SET_PHRASE
            if is_medieval_japanese
            else LOCAL_MEDIEVAL_CENTRAL_ASIAN_ARMED_BODY_VISIBLE_SET_PHRASE
            if is_medieval_central_asian
            else LOCAL_EARLY_ANCIENT_CHINESE_ARMED_BODY_VISIBLE_SET_PHRASE
            if is_early_ancient_chinese
            else LOCAL_ACHAEMENID_EGYPTIAN_ARMED_BODY_VISIBLE_SET_PHRASE
            if is_achaemenid_egyptian
            else LOCAL_ARMED_BODY_VISIBLE_SET_PHRASE
        )
    if _local_scene_requests_armed_figures(p) and "SELECTED PERIOD WEAPON LOCK" not in p:
        p = p.rstrip() + " " + _local_selected_period_weapon_phrase(p)
    p = re.sub(r"\s{2,}", " ", p).strip()
    return p


