def _outdoor_location_comfyui_first_prompt(prompt: str) -> str:
    scene = _local_scene_excerpt(prompt)
    place = _local_prompt_field(prompt, "Exact place")
    subject = _local_prompt_field(prompt, "Main subject")
    required_bits = []
    if place:
        required_bits.append(f"Required Exact place: {place}.")
    if subject:
        required_bits.append(f"Required main subject: {subject}.")
    if scene:
        required_bits.append(f"Required Scene action: {scene}.")
    single_clause = ""
    if scene and not _local_scene_requests_group(prompt):
        single_clause = (
            "The Scene is not a group request. Required composition: EXACTLY ONE "
            "visible living human figure total in the whole image: one person, "
            "one head, one face, one torso. All other people are absent; no second "
            "face, second torso, companion, paired men, lineup, attendants, or "
            "extra bystanders. The background behind the one subject contains zero "
            "human silhouettes, zero distant people, and zero partial bodies; use "
            "only the named exterior place, buildings, terrain, weather, smoke, "
            "or objects behind the subject. "
        )
    action_clause = ""
    if re.search(
        r"\b(holding|holds|held|clutching|clutches|clutched|carrying|carries|"
        r"carried|gripping|grips|gripped|household\s+goods|personal\s+belongings|"
        r"bundle|box|basket|sack)\b",
        scene,
        re.IGNORECASE,
    ):
        action_clause += (
            "Hands visibly grip the named carried object. Household goods or "
            "personal belongings appear as a tied cloth bundle, small wooden box, "
            "bedding roll, basket, or tied sack in the hands, not as blank hands "
            "or unrelated documents. "
        )
    if re.search(
        r"\b(smoke|soot|ash|embers?|flames?|fire|burning|burned|rain|storm|"
        r"dust|mud|ruin|damage)\b",
        scene + " " + place,
        re.IGNORECASE,
    ):
        action_clause += (
            "The named weather, fire, smoke, ash, embers, burn damage, dust, "
            "ruin, or damage must be visible in the same outdoor space. "
        )
    if re.search(r"\b(burning|burned|fire|flames?|embers?|ash|soot)\b", scene + " " + place, re.IGNORECASE):
        action_clause += (
            "Fire-damage evidence is mandatory: charred blackened timber, scorch "
            "marks on wooden buildings, ash on the ground, smoke haze or smoke "
            "plumes, and small glowing embers in the air. Do not show a clean "
            "undamaged street when the Scene names burned, fire, ash, soot, or embers. "
        )
    required = " ".join(required_bits)
    return (
        "OUTDOOR LOCATION FIRST RULE: "
        f"{required} "
        "The named outdoor place is the first readable composition subject. Use "
        "an exterior story frame with the camera standing on the named outdoor "
        "ground. Open sky, smoke-filled outdoor air, weather, dust, or horizon "
        "must be visible above or behind the people. Buildings, gates, posts, "
        "and eaves may appear only as exterior side framing or partial roof "
        "edges, not as a full overhead ceiling. Do not render a timber room, "
        "interior floor, interior plaster wall, corridor, covered veranda, "
        "roofed porch, studio portrait, or indoor portrait unless the Scene "
        "explicitly names an interior. "
        f"{single_clause}{action_clause}"
        "All visible robe and cloth chest, sleeve, shoulder, and sash surfaces are "
        "plain unmarked fabric only: folds, seams, dust, stains, and shadow; no "
        "emblem, crest, flower mark, badge, mon, pin, medallion, or decorative "
        "chest symbol. "
        "Historical outdoor air, roof gaps, skylines, and street edges contain no "
        "power poles, utility poles, telephone poles, overhead wires, roof-to-roof "
        "cables, or straight black cable lines. Any tiny distant vertical mark in "
        "a field, road, ridge, roof gap, or sky gap resolves as a broken reed, "
        "tree trunk, fence slat, smoke edge, or irregular brush texture with no "
        "crossarm, no insulator, no hanging cable, and no wire connection. "
        "Gates, walls, lintels, and eaves "
        "stay continuous unlabeled material: no signboard, plaque, title panel, "
        "shop sign, street sign, written banner, hanging label strip, or character marks. "
        "In premodern scenes, visible footwear is period-local sandals, straw "
        "sandals, simple boots, tabi, bare feet, or rough leather/cloth footwear; "
        "no glossy black dress shoes, office shoes, loafers, sneaker soles, or "
        "rubber soles."
    )

