def _append_unique_negative(base: str, extra: str) -> str:
    base = (base or "").strip()
    extra = (extra or "").strip()
    if not extra:
        return base
    if not base:
        return extra
    lower = base.lower()
    terms = [term.strip() for term in extra.split(",") if term.strip()]
    missing = [term for term in terms if term.lower() not in lower]
    if not missing:
        return base
    return base.rstrip(" ,") + ", " + ", ".join(missing)


