def _flux2_klein_clean_text(value: str) -> str:
    out = re.sub(r"\s+", " ", value or "").strip(" ;,.")
    replacements = (
        (r"400\s*[~\-]\s*415\s*(?:년|year)?(?:\s+고구려사\s+흐름)?", "400-415 CE"),
        (r"신라\s*종발성", "Silla Jongbalseong fortress area"),
        (r"광개토대왕", "King Gwanggaeto"),
        (r"내물\s*마립간", "Naemul Maripgan"),
        (r"실성왕", "King Silseong"),
        (r"복호", "Prince Bokho"),
        (r"큐시트\s*연도\s*=\s*400\s*[~\-]\s*415\s*년", "400-415 CE source cue"),
        (r"배경\s*=\s*신라\s*종발성", "setting cue: Silla Jongbalseong"),
        (r"핵심인물\s*=\s*광개토대왕", "main figure cue: King Gwanggaeto"),
        (r"주요인물\s*=[^;]+", "supporting figures from the Silla submission episode"),
        (r"\bstorehouse\s+yard\b", "open rice-bundle yard with roof edges, posts, ground, and mountains"),
        (r"\bwooden\s+storehouse\b", "cropped roof-edge storage shelter with posts and shadow"),
        (r"\bdomain\s+storehouses?\b", "open rice-bundle yards with roof edges and posts"),
        (r"\bstorehouses?\b", "open rice-bundle yards with roof edges and posts"),
    )
    for pattern, repl in replacements:
        out = re.sub(pattern, repl, out, flags=re.IGNORECASE)
    out = re.sub(r"[가-힣一-龥ぁ-んァ-ン]+", " ", out)
    out = re.sub(r"\s*;\s*", "; ", out)
    out = re.sub(r"\s+", " ", out).strip(" ;,.")
    return out


def _flux2_klein_safe_scene(scene: str, source_prompt: str = "") -> str:
    out = _flux2_klein_clean_text(scene)
    context_text = source_prompt or scene
    if _flux2_klein_is_historical_japanese_context(context_text):
        sword_replacement = "curved Japanese sword in a plain scabbard"
    elif _local_is_arpad_hungary_context(context_text):
        sword_replacement = "one simple iron sword"
    elif _local_is_high_medieval_europe_context(context_text):
        sword_replacement = "period European arming sword"
    elif _local_is_early_ne_asian_or_ep13_context(context_text):
        sword_replacement = "short straight iron blade"
    else:
        sword_replacement = "period-local sword"
    if _local_is_arpad_hungary_context(context_text):
        crown_replacement = "one plain metal crown"
    elif _local_is_high_medieval_europe_context(context_text):
        crown_replacement = "12th-century open circlet crown"
    elif _local_scene_is_explicit_ancient_egypt_context(context_text):
        crown_replacement = "ancient Egyptian crown"
    elif _local_is_early_ne_asian_or_ep13_context(context_text):
        crown_replacement = "early Silla gold crown fragment"
    else:
        crown_replacement = "period-local crown"
    rewrites = (
        (
            r"\byoung\s+King\s+Jangsu\s+placing\s+his\s+(?:hands|sleeve-covered\s+contact)\s+firmly\s+on\s+a\s+massive,\s*heavy\s+iron\s+steering\s+wheel\b|"
            r"\bmassive,\s*heavy\s+iron\s+steering\s+wheel\b|\bsteering\s+wheel\b",
            "low wooden succession command board with blank route cords, separated stone markers, dull iron rim weights, and closed sleeve cuffs at the back edge",
        ),
        (
            r"\ba\s+curtain\s+rising\s+slowly\s+on\s+a\s+stage\s+filled\s+with\s+broken\s+weapons\s+and\s+skulls\b|"
            r"\bcurtain\s+rising\s+slowly\s+on\s+a\s+stage\s+filled\b|\bstage\s+filled\s+with\s+broken\s+weapons\s+and\s+skulls\b|"
            r"\btitle\s+card\s+for\s+episode\s+\d+\b",
            "dark battlefield threshold with broken spear shafts, short straight iron blades, shield fragments, packed earth, ash, smoke, and palisade shadow",
        ),
        (
            r"\brazor[-\s]*sharp\s+surgical\s+blade\s+gleaming\s+under\s+a\s+harsh,\s*cold,\s*clinical\s+light\b|"
            r"\bsurgical\s+blade\b|\bclinical\s+light\b",
            "short straight early Korean iron blade lying on a rough whetstone under cold oil-lamp light",
        ),
        (
            r"\b(?:two\s+smaller\s+kings|two\s+smaller\s+rulers)\s+shaking\s+(?:hands|sleeve-covered\s+contact)\s+nervously\b|"
            r"\b(?:two\s+smaller\s+kings|two\s+smaller\s+rulers)\s+shaking\s+sleeve-covered\s+arm\s+gesture\s+nervously\b|"
            r"\bshaking\s+(?:hands|sleeve-covered\s+contact|sleeve-covered\s+arm\s+gesture)\b",
            "two smaller rulers facing each other across a low table with hands hidden inside closed sleeves and one blank cord-tied pact token between them",
        ),
        (
            r"\ba\s+diplomat\s+handing\s+over\s+a\s+peace\s+treaty\b|"
            r"\bhanding\s+over\s+a\s+peace\s+treaty\b|\bpeace\s+treaty\b",
            "one blank cord-tied wooden pact bundle lying on a low table between period-local envoys with sleeve edges kept back from the object",
        ),
        (
            r"\b(?:beautiful\s+)?ancient\s+treaty\s+document\b|\btreaty\s+document\b",
            "blank cord-tied wooden pact bundle",
        ),
        (
            r"\bcalloused,\s*bleeding\s+(?:hands|sleeve-covered\s+contact)\s+gripping\s+heavy\s+stones\s+on\s+a\s+steep,\s*freezing\s+incline\b|"
            r"\bbleeding\s+(?:hands|sleeve-covered\s+contact)\s+gripping\s+heavy\s+stones\b",
            "two heavy rough stones on a steep freezing incline beside torn blood-stained sleeve cloth wraps, rope loops, packed mud, frost, and contact shadows",
        ),
        (
            r"\ba\s+beautiful\s+stained[-\s]*glass\s+window\s+covering\s+a\s+dark,\s*rotting,\s*and\s*bloody\s+brick\s+wall\b|"
            r"\bstained[-\s]*glass\s+window\b",
            "charred ancient mud-plaster wall partly covered by a torn plain hemp screen, smoke shadow, dark red stains, and broken weapon debris",
        ),
        (r"\bbrick\s+wall\b", "packed-earth plaster wall"),
        (r"\bshattered\s+glass\b|\bglass\b", "broken polished bronze mirror fragments"),
        (r"\btextbook\s+page\b|\bhistory\s+text\b|\bhistory\s+book\b|\bancient\s+history\s+book\b", "tied wooden record tablets"),
        (r"\bscalpel\b", "narrow iron knife blade"),
        (r"\bvelvet(?:-like)?\b", "dark plain cloth"),
        (r"\bchess\s+piece\b", "small carved wooden campaign marker"),
        (r"\bmap\s+of\s+Silla\b|\bancient\s+map\b|\bmap\b|\bkorean\s+peninsula\b", "low wooden campaign board with raised clay markers and cords"),
        (r"\broyal\s+emblem\b|\bemblem\b", "plain Silla tribute token"),
        (r"\bflag\b|\bbanner\b", "blank cloth military standard"),
        (r"\bwooden\s+storehouse\b", "cropped roof-edge storage shelter with posts and shadow"),
        (r"\bstorehouse\s+yard\b", "open rice-bundle yard with roof edges, posts, ground, and mountains"),
        (r"\bstorehouses?\b", "open rice-bundle yards with roof edges and posts"),
        (r"\bmassive,\s*imposing\s+gates?\s+of\s+Goguryeo\s+fortress\b", "rough roofless timber palisade entrance of a Goguryeo frontier fortress"),
        (r"\biron[-\s]*studded\s+wooden\s+gates?\b|\bgates?\b", "rough timber palisade entrance"),
        (r"\bhuge\s+throne\b|\bthrone'?s?\b|\bthrone\b", "low wooden command dais"),
        (r"\bcrown\b", crown_replacement),
        (r"\blong,\s*heavy\s+sword\b|\bsharp\s+sword\b|\bsword\b", sword_replacement),
        (r"\bhand\s+moving\b", "sleeve-covered arm moving"),
        (r"\bhand\s+tightly\s+gripping\b", "small sleeve-covered grip holding"),
        (r"\bhands\b", "sleeve-covered contact"),
    )
    for pattern, repl in rewrites:
        out = re.sub(pattern, repl, out, flags=re.IGNORECASE)
    return re.sub(r"\s+", " ", out).strip(" ;,.")


def _flux2_klein_context(prompt: str) -> tuple[str, str, str, str, str]:
    year = _flux2_klein_clean_text(_local_prompt_field(prompt, "Year/period"))
    if re.search(r"400\s*[-~]\s*415", year, re.IGNORECASE):
        year = "400-415 CE"
    year = year or "the stated historical period"

    place = _flux2_klein_clean_text(_local_prompt_field(prompt, "Exact place"))
    place = place or "the stated historical place"

    culture = _flux2_klein_clean_text(_local_prompt_field(prompt, "Culture scope"))
    if not culture:
        if _flux2_klein_is_midgley_modern_us_context(prompt):
            culture = "1920s-1940s United States scientific and industrial world"
        elif _flux2_klein_is_historical_japanese_context(prompt):
            culture = "historical Japanese warrior society"
        elif _local_is_high_medieval_europe_context(prompt):
            culture = "high medieval European and Holy Roman crusading world"
        elif _local_is_late_medieval_western_europe_context(prompt):
            culture = "late medieval Western European world"
        elif _local_is_early_modern_europe_context(prompt):
            culture = "early modern European world"
        elif re.search(
            r"\b(Goguryeo|Silla|Baekje|Wa|Korea|Korean|Gaya|Buyeo)\b|"
            r"(고구려|신라|백제|왜|가야|부여)",
            prompt or "",
            re.IGNORECASE,
        ):
            culture = "Goguryeo, Silla, Baekje, and Wa ancient Northeast Asian political world"
        else:
            culture = "the stated historical culture"

    subject = _flux2_klein_clean_text(_local_prompt_field(prompt, "Main subject"))
    subject = subject or "the Scene-named historical subject"

    scene = _local_prompt_field(prompt, "Scene") or _local_scene_excerpt(prompt, limit=700)
    scene = _flux2_klein_safe_scene(scene, prompt)
    if _flux2_klein_is_midgley_refrigerator_gas_scene(prompt):
        subject = scene = (
            "three-quarter rear view of one plain unmarked 1930s-1940s rounded "
            "metal refrigerator in a bare 1940s domestic kitchen corner, with the "
            "side-rear vent slats visibly emitting a thick pale noxious gas plume"
        )
    elif _flux2_klein_is_midgley_dark_kitchen_fog_scene(prompt):
        subject = scene = (
            "an empty dark 1940s domestic kitchen at night with plain cupboards, "
            "one unmarked metal refrigerator, window darkness, and heavy fog rolling "
            "across the floor"
        )
    elif _flux2_klein_is_midgley_refrigerator_workbench_scene(prompt):
        subject = scene = (
            "one bare wooden workbench holding an unmarked refrigerator compressor, "
            "coiled copper tubing, brass fittings, a compass, a plain ruler, and "
            "calipers, with no paper sheet"
        )
    elif _flux2_klein_is_midgley_freon_mist_container_scene(prompt):
        subject = scene = (
            "one sealed heavy glass container on a bare wooden workbench, with frosty "
            "blue mist swirling inside and no label"
        )
    elif _flux2_klein_is_midgley_safe_refrigeration_kitchen_scene(prompt):
        subject = scene = (
            "one plain unmarked rounded 1940s metal refrigerator standing in a clean "
            "1940s domestic kitchen, with simple cupboards, cold vapor, and no logos"
        )
    elif _flux2_klein_is_midgley_period_globe_cloche_scene(prompt):
        subject = scene = (
            "one physical period classroom globe inside a clear glass bell jar on a "
            "bare wooden workbench, with green and purple vapor reflections"
        )
    elif _flux2_klein_is_midgley_closed_book_scene(prompt):
        subject = scene = (
            "one closed plain old cloth-bound book lying flat on a bare dark wooden "
            "workbench, with blank cover, closed page block edge, dust puff, wood "
            "grain, and contact shadow only"
        )
    elif _flux2_klein_is_midgley_marionette_scene(prompt):
        subject = scene = (
            "one small plain wooden marionette puppet lying on a bare dark wooden "
            "workbench under taut strings, with one tiny plain open scissors crossing "
            "one string"
        )
    elif _flux2_klein_is_midgley_blueprint_flaw_scene(prompt):
        subject = scene = (
            "one plain magnifying glass resting on a blank blue-gray evidence sheet "
            "on a bare dark wooden workbench, centered over one dark irregular flaw blot"
        )
    elif _flux2_klein_is_midgley_grease_carving_scene(prompt):
        subject = scene = (
            "one unmarked carved metal relief plate lying flat on a bare dark wooden "
            "workbench, with thick black grease partly wiped away by one dirty cloth "
            "rag and one plain wooden scraper"
        )
    scene = scene or "the Scene-named historical action"
    return year, place, culture, subject, scene


def _flux2_klein_style_clause() -> str:
    return (
        "Render as a 2D adult graphic novel illustration with extra-thick black ink "
        "contour lines, bold silhouettes, hard shadow masses, matte cel shading, "
        "gritty brush texture, desaturated historical colors, and dark documentary lighting."
    )


def _flux2_klein_md_style_clause() -> str:
    return (
        "Render as full-bleed 2D historical ink-and-cel with thick black contours "
        "only around visible objects and figures, hard shadows, matte cel shading, "
        "and dark light."
    )


def _flux2_klein_9b_photoreal_positive_prompt(source_prompt: str) -> str:
    cut_prompt = re.sub(r"\s+", " ", (source_prompt or "").strip()) or "an image"
    japanese_myth_guard = ""
    japanese_myth_person = bool(re.search(
        r"\b(?:Izanagi|Izanami|male\s+deity|female\s+deity|deity|god|goddess|"
        r"kami\s+(?:elder|elders|hand)|divine\s+hand|right\s+hand|left\s+hand|"
        r"portrait|elders?)\b",
        cut_prompt,
        re.IGNORECASE,
    ))
    japanese_myth_artifact = bool(re.search(
        r"\b(?:Ame-no-nuboko|spear|jeweled\s+spear|sacred\s+artifact|artifact)\b",
        cut_prompt,
        re.IGNORECASE,
    ))
    japanese_myth_place = bool(re.search(
        r"\b(?:Takamagahara|heavenly|heaven|clouds?|palace|creation|divine)\b",
        cut_prompt,
        re.IGNORECASE,
    ))
    if japanese_myth_person:
        japanese_myth_guard = (
            "For Japanese creation myth or divine subjects, use ancient Japanese myth visual language: "
            "plain sacred wooden architecture, shimenawa-like rope only when needed, simple white or earth-tone "
            "ritual robes, dark tied hair, restrained Jomon/Yayoi/Kofun-plausible materials, and a Shinto-origin "
            "myth atmosphere. Do not use European, Christian, Greco-Roman, fantasy-RPG, cathedral, basilica, "
            "golden dome, cross, marble-column, Western palace, Chinese imperial palace, modern room, or modern "
            "window visual language."
        )
    elif japanese_myth_artifact:
        japanese_myth_guard = (
            "For Japanese creation myth artifacts, use restrained ancient Japanese ritual materials: dark wood, "
            "aged bronze, dull gold, mist, cloud light, and simple sacred presentation. Keep it object-only unless "
            "the cut brief explicitly names a hand or person. Do not use European, Christian, Greco-Roman, "
            "fantasy-RPG, cathedral, basilica, golden dome, cross, Western palace, Chinese imperial palace, "
            "modern room, or modern product-ad visual language."
        )
    elif japanese_myth_place:
        japanese_myth_guard = (
            "For Japanese creation myth places, use the exact place named in the cut brief with restrained "
            "natural materials. If the cut brief says empty, no building, no platform, or no people, keep the "
            "scene empty and do not add a platform, bench, shrine, building, or figure. Use a raised wooden "
            "ritual platform only when the cut brief explicitly names one. This is a place shot, not a person "
            "portrait. Keep it free of people, priests, robed figures, seated figures, faces, hands, and bodies "
            "unless the cut brief explicitly names them. Do not use European, Christian, "
            "Greco-Roman, fantasy-RPG, cathedral, basilica, golden dome, cross, marble-column, Western palace, "
            "Chinese imperial palace, modern room, or modern window visual language."
        )
    no_people = (
        "If the cut brief does not explicitly name a person, face, hand, crowd, "
        "rider, or human action, keep the frame completely free of people, faces, "
        "hands, and bodies."
    )
    no_animals = (
        "If the cut brief does not explicitly name an animal, horse, mount, or bird, "
        "keep the frame completely free of animals."
    )
    return re.sub(
        r"\s+",
        " ",
        (
            "FLUX2 KLEIN 9B PHOTOREAL CUT LOCK. "
            f"Depict this exact cut brief as the first visible subject: {cut_prompt} "
            "Use photorealistic live-action documentary photography, realistic natural materials, "
            "cinematic light, sharp subject focus, realistic shadows, and a serious historical documentary mood. "
            "The result must visibly match the cut brief, not a generic Japanese road, gate, shrine, traveler, "
            "mounted rider, snowy path, or reused composition from the previous cut. "
            "Do not replace the named subject with an unrelated landscape, doorway, horse, rider, gate, temple, "
            "portrait, or symbolic filler. "
            f"{japanese_myth_guard} "
            f"{no_people} {no_animals} "
            "If a human or animal is explicitly required, keep natural anatomy only: one head, one torso, "
            "two arms, two legs for each human, normal hands with one thumb and four fingers when visible, "
            "and four legs for each horse or animal. "
            "No readable text, no pseudo-text, no logo, no watermark, no signs, no labels. "
            "Every style cue means real camera photography only, with natural lens rendering and realistic sensor detail."
        ),
    ).strip()


def _flux2_klein_9b_photoreal_negative_prompt(base_negative: str) -> str:
    banned_negative_terms = {
        "photorealistic",
        "photorealistic photo",
        "photorealism",
        "photographic",
        "photographic still",
        "live-action still",
        "raw photo",
        "raw camera photo",
        "realistic photography",
        "documentary photography",
    }
    kept: list[str] = []
    seen: set[str] = set()
    for token in [x.strip() for x in (base_negative or "").split(",") if x.strip()]:
        key = token.lower()
        if key in banned_negative_terms:
            continue
        if key not in seen:
            seen.add(key)
            kept.append(token)
    return _append_unique_negative(
        ", ".join(kept),
        (
            "illustration, anime, manga, cartoon, graphic novel, comic-book art, "
            "ink-and-cel, cel shading, thick black outlines, black ink contour lines, "
            "painted illustration, sketch, watercolor, storybook, 3D render, CGI, "
            "European cathedral, Christian church, basilica, chapel, Christian cross, crucifix, "
            "golden dome, domed cathedral, onion dome, mosque dome, Greco-Roman temple, "
            "marble columns, Western palace, European royal palace, fantasy castle, fantasy staff, "
            "Western goddess, Western angel, haloed saint, Chinese imperial palace, modern room, "
            "modern window wall, modern glass window, "
            "unexpected person in empty place shot, robed person in empty landscape, priest on platform, "
            "seated figure on platform, portrait replacing place shot, "
            "wooden platform when not requested, raised platform when not requested, deck when not requested, "
            "bench when not requested, table when not requested, manmade structure in empty landscape, "
            "padlock when not requested, lock when not requested, metal object in mud when not requested, "
            "chain when not requested, random artifact in mud, debris object replacing empty mud, "
            "generic Japanese road replacing cut subject, repeated previous composition, "
            "mounted rider when not requested, horse when not requested, gate when not requested, "
            "shrine when not requested, temple when not requested, unrelated scenery, "
            "wrong subject, missing named subject"
        ),
    )


def _flux2_klein_is_midgley_modern_us_context(prompt: str) -> bool:
    text = prompt or ""
    fields = " ".join(
        bit
        for bit in (
            _local_prompt_field(text, "Year/period"),
            _local_prompt_field(text, "Exact place"),
            _local_prompt_field(text, "Scene evidence"),
            _local_prompt_field(text, "Main subject"),
            _local_prompt_field(text, "Scene"),
            text,
        )
        if bit
    )
    return bool(
        re.search(
            r"\b(?:Worthington,\s*Ohio|Thomas\s+Midgley|Midgley|"
            r"The\s+Inventor\s+Strangled|tetraethyl|leaded\s+gas|Freon|CFCs?|"
            r"1920s|1930s|1940s|1944\s+AD)\b",
            fields,
            re.IGNORECASE,
        )
    )


