def _flux2_klein_is_historical_japanese_context(prompt: str) -> bool:
    if _flux2_klein_is_midgley_modern_us_context(prompt):
        return False
    if re.search(
        r"\b(?:Imperial\s+Russia|Romanov|Rasputin|Russian|Russia|Petrograd|Tsar|Neva|cyanide)\b",
        prompt or "",
        re.IGNORECASE,
    ):
        return False

    global_match = re.search(
        r"(?:^|;\s*|\|\|\s*)Global\s+visual\s+world\s*:\s*(.*?)(?=;\s*(?:Place\s+scope|"
        r"Culture\s+scope|Material\s+culture|Continuity\s+rule|Year/period|Exact\s+place|"
        r"Scene\s+evidence|Style|Main\s+subject|Scene)\s*:|\s+\|\|\s+|$)",
        prompt or "",
        re.IGNORECASE | re.DOTALL,
    )
    global_world = re.sub(r"\s+", " ", global_match.group(1)).strip(" ;,") if global_match else ""
    early_year = _local_prompt_field(prompt, "Year/period")
    early_place = _local_prompt_field(prompt, "Exact place")
    early_culture = _local_prompt_field(prompt, "Culture scope")
    early_subject = _local_prompt_field(prompt, "Main subject")
    early_scene = _local_scene_excerpt(prompt, limit=500)
    early_field_text = " ".join(
        part for part in (global_world, early_year, early_place, early_culture, early_subject, early_scene) if part
    )
    if (
        re.search(
            r"\b(?:Akechi|Yamazaki|Mitsuhide|Nobunaga|Oda|Honno-?ji|"
            r"Azuchi(?:[-\s]*Momoyama)?|Momoyama|Toyotomi|Hideyoshi|"
            r"Sengoku|Tensho|Japan|Japanese)\b",
            early_field_text,
            re.IGNORECASE,
        )
        and re.search(
            r"\b(?:15\d{2}|16\d{2}|15\d0s|16\d0s|Sengoku|Tensho|"
            r"Azuchi[-\s]*Momoyama|Momoyama)\b",
            early_field_text,
            re.IGNORECASE,
        )
    ):
        return True
    if _local_is_early_ne_asian_or_ep13_context(prompt):
        return False
    if _local_is_medieval_japanese_context(prompt):
        return True
    year = _local_prompt_field(prompt, "Year/period")
    place = _local_prompt_field(prompt, "Exact place")
    culture = _local_prompt_field(prompt, "Culture scope")
    subject = _local_prompt_field(prompt, "Main subject")
    scene = _local_scene_excerpt(prompt, limit=500)
    field_text = " ".join(part for part in (year, place, culture, subject, scene) if part)
    context_text = " ".join(part for part in (global_world, field_text) if part).strip()
    explicit_japan = bool(
        re.search(
            r"\b(Japan|Japanese|Edo|Kamakura|Muromachi|Sengoku|Kyoto|"
            r"Yamazaki|Akechi|Mitsuhide|Nobunaga|Oda|Honno-?ji|Tensho|"
            r"Azuchi(?:[-\s]*Momoyama)?|Momoyama|Toyotomi|Hideyoshi|"
            r"samurai|ashigaru|daimyo|daimyō|shogun|shogunate|warrior\s+household)\b|"
            r"(日本|江戸|鎌倉|室町|戦国|戰國|京都|侍|武士|将軍|足軽|大名)",
            context_text or field_text,
            re.IGNORECASE,
        )
    )
    has_field_historical = bool(
        re.search(
            r"\b(?:c\.\s*)?(?:11\d{2}|12\d{2}|13\d{2}|14\d{2}|15\d{2}|"
            r"16\d{2}|17\d{2}|18\d{2})\b|"
            r"\b(?:15\d0s|16\d0s|Kamakura|Muromachi|Sengoku|Edo|"
            r"Azuchi[-\s]*Momoyama|Momoyama|medieval|early[-\s]*modern|Tensho|"
            r"historical\s+Japanese)\b",
            context_text or field_text,
            re.IGNORECASE,
        )
    )
    if explicit_japan and has_field_historical:
        return True
    if _local_is_modern_context(prompt):
        return False
    if (
        not explicit_japan
        and (
            _local_is_high_medieval_europe_context(prompt)
            or _local_is_late_medieval_western_europe_context(prompt)
            or _local_is_early_modern_europe_context(prompt)
        )
    ):
        return False
    text = context_text or field_text or (prompt or "")
    has_japan = bool(
        re.search(
            r"\b(Japan|Japanese|Edo|Kamakura|Muromachi|Sengoku|Kyoto|"
            r"Yamazaki|Akechi|Mitsuhide|Nobunaga|Oda|Honno-?ji|Tensho|"
            r"Azuchi(?:[-\s]*Momoyama)?|Momoyama|Toyotomi|Hideyoshi|"
            r"samurai|ashigaru|daimyo|daimyō|shogun|shogunate|warrior\s+household)\b|"
            r"(日本|江戸|鎌倉|室町|戦国|戰國|京都|侍|武士|将軍|足軽|大名)",
            text,
            re.IGNORECASE,
        )
    )
    has_historical = bool(
        re.search(
            r"\b(?:c\.\s*)?(?:11\d{2}|12\d{2}|13\d{2}|14\d{2}|15\d{2}|"
            r"16\d{2}|17\d{2}|18\d{2})\b|"
            r"\b(?:15\d0s|16\d0s|Kamakura|Muromachi|Sengoku|Edo|"
            r"Azuchi[-\s]*Momoyama|Momoyama|medieval|early[-\s]*modern|"
            r"historical\s+Japanese)\b",
            text,
            re.IGNORECASE,
        )
    )
    return bool(has_japan and has_historical)


def _flux2_klein_is_20th_century_us_science_industrial_context(text: str) -> bool:
    p = text or ""
    if _flux2_klein_is_historical_japanese_context(p):
        return False
    if re.search(
        r"\b(?:Imperial\s+Russia|Romanov|Rasputin|Russian|Russia|Neva|cyanide|"
        r"monk|aristocrats?|cellar|freezing\s+river|river\s+ice|poisoned\s+goblet)\b",
        p,
        re.IGNORECASE,
    ):
        return False
    scan = re.sub(r"\bepisode\s*=[^;]+;?", " ", p, flags=re.IGNORECASE)
    scan = re.sub(r"\bExact\s+place\s*:[^;]+;?", " ", scan, flags=re.IGNORECASE)
    scan = re.sub(r"\bplace\s*=[^;]+;?", " ", scan, flags=re.IGNORECASE)
    has_time = bool(
        re.search(
            r"\b(?:19[0-5]\d|1920s|1930s|1940s|20th\s+century|early\s+20th)\b",
            scan,
            re.IGNORECASE,
        )
    )
    has_subject = bool(
        re.search(
            r"\b(?:Thomas\s+Midgley|Midgley|"
            r"laborator(?:y|ies)|scientist|chemist|chemical|test\s*tube|flask|"
            r"factory|industrial|gasoline|leaded|tetraethyl|Freon|CFC|refrigerator|"
            r"automobile|car|engine|hospital|polio|wheelchair|desk\s+lamp|chalkboard|"
            r"blackboard|blueprint|American\s+city\s+street|city\s+street|living\s+room|"
            r"suburban|toxic\s+gas|fuel|atmosphere|Earth\s+from\s+space|globe|brain|"
            r"medical|pulley|gear|assistive\s+rig|factory\s+worker|corporate\s+executive|"
            r"heavy\s+cord|satellite|protective\s+shield|glowing\s+blue\s+shield|graph\s+paper|calendar|"
            r"virus|nerve\s+cells|thumbs-up|data\s+connections|spine|human\s+heart|"
            r"engineering\s+paper|wax\s+seal|police\s+report|Earth\s+surrounded)\b",
            scan,
            re.IGNORECASE,
        )
    )
    return bool(has_time and has_subject)


