def _flux2_klein_is_ondal_goguryeo_context(prompt: str) -> bool:
    text = prompt or ""
    if (
        _flux2_klein_is_midgley_modern_us_context(text)
        or _flux2_klein_is_historical_japanese_context(text)
        or _flux2_klein_is_imperial_russia_teaser_context(text)
    ):
        return False
    fields = " ".join(
        bit
        for bit in (
            _local_prompt_field(text, "Year/period"),
            _local_prompt_field(text, "Exact place"),
            _local_prompt_field(text, "Culture scope"),
            _local_prompt_field(text, "Scene evidence"),
            _local_prompt_field(text, "Main subject"),
            _local_prompt_field(text, "Scene"),
            text,
        )
        if bit
    )
    return bool(
        re.search(
            r"\b(?:Ondal|Pyeonggang|Pyeongwon|590\s*year|590\s*CE|590\s*AD)\b|"
            r"(온달|평강|평원왕)",
            fields,
            re.IGNORECASE,
        )
    )


