def _sanitize_flux2_klein_ondal_goguryeo_positive_final(prompt: str) -> str:
    out = prompt or ""
    replacements: tuple[tuple[str, str], ...] = (
        (
            r"\ba\s+dark\s+ancient\s+chessboard\s+with\s+a\s+single\s+bloody\s+pawn\b",
            (
                "a low Goguryeo command workbench with one blood-dark clay counter, "
                "plain pebble counters, cord knots, bronze weights, soot, dust, "
                "and hard oil-lamp shadow"
            ),
        ),
        (
            r"\bdark\s+ancient\s+chessboard\b|\bancient\s+chessboard\b|\bchessboard\b",
            "low Goguryeo command workbench",
        ),
        (
            r"\bsingle\s+bloody\s+pawn\b|\bbloody\s+pawn\b|\bpawn\b",
            "blood-dark plain clay counter",
        ),
    )
    for pattern, replacement in replacements:
        out = re.sub(pattern, replacement, out, flags=re.IGNORECASE)

    sentence_parts = re.split(r"(?<=[.!?])\s+", out)
    drop_sentence = re.compile(
        r"\b(?:zero|no|without|avoid|forbidden|exclude|not|never|absent)\b",
        re.IGNORECASE,
    )
    kept = [part for part in sentence_parts if part and not drop_sentence.search(part)]
    out = " ".join(kept)

    residual_forbidden = re.compile(
        r"\b(?:switch(?:es)?|outlets?|electric|modern|text|writing|glyphs?|"
        r"letters?|characters?|signboards?|plaques?|documents?|paper|"
        r"lintels?|headers?|eaves?|panels?|marks?|symbols?|"
        r"guns?|rifles?|roman|european|monster)\b",
        re.IGNORECASE,
    )
    sentence_parts = re.split(r"(?<=[.!?])\s+", out)
    kept = [part for part in sentence_parts if part and not residual_forbidden.search(part)]
    out = " ".join(kept)

    out = re.sub(r"\s+", " ", out).strip(" ;,.")
    framing = (
        "Goguryeo camera framing keeps upper door zones cropped away or merged "
        "into continuous rough timber beam grain, with open sky, side roof "
        "fragments, plain door planks, rope pulls, cracked plaster, packed "
        "earth, dust, soot, and shadow as the visible surroundings"
    )
    object_first = re.search(
        r"\b(?:object-only|top-down|macro|still-life|evidence|"
        r"workbench fills the frame|frame is filled by irregular debris)\b",
        out,
        re.IGNORECASE,
    )
    if not object_first and framing.lower() not in out.lower():
        out = f"{out}. {framing}" if out else framing
    return out


def _flux2_klein_ondal_direct_first_scene(prompt: str) -> bool:
    scene = " ".join(
        bit
        for bit in (
            _local_prompt_field(prompt or "", "Scene"),
            _local_scene_excerpt(prompt or "", limit=700),
            prompt or "",
        )
        if bit
    ).lower()
    return bool(
        (
            re.search(r"\bspear\b", scene)
            and re.search(r"\bpierc", scene)
            and re.search(r"\barmor\b", scene)
        )
        or re.search(r"\bchinese\s+dragon\b|\bdragon\b.*\b(?:banner|standard|pole)", scene)
    )


