def _flux2_klein_japanese_text_surface_risk(text: str) -> bool:
    return bool(
        re.search(
            r"\b(?:book|books|woodblock|reader|reading|storyteller|storytelling|"
            r"open\s+page|open\s+pages|page\s+spread|document|documents|paper|"
            r"papers|sheet|sheets|manuscript|records|writing|writes|brush|"
            r"calligraphy|scroll|wall\s+scroll|hanging\s+scroll|poster|signboard|"
            r"signboards|notice|notices|plaque|lintel\s+board|doorjamb\s+tag|"
            r"display|chart|diagram|genealogy\s+board|lineage\s+board|ancestry\s+board|"
            r"family\s+tree|wooden\s+genealogy\s+board|wooden\s+lineage\s+board|"
            r"letter|letters|message|messages|orders?|terms|map|maps|routes?|route\s+markers?|"
            r"wooden\s+route\s+markers?|studying\s+routes?|"
            r"battle\s+plan|tactical\s+board|strategy\s+board|planning\s+board|route\s+mark|"
            r"compass|label|shelves|shelf|bookcase|portrait|picture)\b",
            text or "",
            re.IGNORECASE,
        )
    )


