def _flux2_klein_japanese_prompt_has_living_story_action(text: str) -> bool:
    scan = text or ""
    has_actor = bool(
        re.search(
            r"\b(?:officials?|clerks?|scribes?|samurai|retainers?|messengers?|"
            r"couriers?|envoys?|attendants?|advisers?|advisors?|guards?|"
            r"gatekeepers?|courtiers?|nobles?|daimyo|commander|elder|watchers?|"
            r"men|man|women|woman|people|townspeople|workers?|hands?|fingers?)\b",
            scan,
            re.IGNORECASE,
        )
    )
    has_action = bool(
        re.search(
            r"\b(?:receiv(?:e|es|ing)|present(?:s|ing)?|hand(?:s|ing)?|"
            r"point(?:s|ing)?|lean(?:s|ing)?|strike(?:s|ing)?|arrang(?:e|es|ing)|"
            r"align(?:s|ing)?|tie(?:s|ing)?|pull(?:s|ing)?|grip(?:s|ping)?|"
            r"guard(?:s|ing)?|lock(?:s|ing)?|lift(?:s|ing)?|hover(?:s|ing)?|"
            r"work(?:s|ing)?|bow(?:s|ing)?|kneel(?:s|ing)?|watch(?:es|ing)?|"
            r"wait(?:s|ing)?|frown(?:s|ing)?|stiffen(?:s|ing)?|sprint(?:s|ing)?|"
            r"rush(?:es|ing)?|carry(?:ies|ing)?|clutch(?:es|ing)?|"
            r"stare(?:s|ing)?|argu(?:e|es|ing)|clench(?:es|ing|ed)?)\b",
            scan,
            re.IGNORECASE,
        )
    )
    return has_actor and has_action


