def _flux2_klein_japanese_record_safe_scene_text(scene: str) -> str:
    safe = scene or ""
    replacements = (
        (r"\bsealed\s+court\s+message\b", "closed sealed lacquered box"),
        (r"\bsealed\s+message\b", "closed sealed lacquered box"),
        (r"\blifts?\s+a\s+court\s+box\s+lid\b", "lifts the rim of a closed plain court box while its interior stays dark"),
        (r"\blifts?\s+the\s+court\s+box\s+lid\b", "lifts the rim of a closed plain court box while its interior stays dark"),
        (r"\bopens?\s+a\s+court\s+box\b", "checks a closed plain court box with the interior hidden in shadow"),
        (r"\bbox\s+lid\b", "closed box rim"),
        (r"\btied\s+papers?\b", "dark tan cord-tied cloth packet sacks"),
        (r"\bsealed\s+papers?\b", "dark tan cord-tied cloth packet sacks"),
        (r"\bfolded\s+papers?\b", "dark tan cord-tied cloth packet sacks"),
        (r"\bsealed\s+certificates?\b", "closed plain lacquered certificate box"),
        (r"\brank\s+certificates?\b", "closed plain lacquered rank box"),
        (r"\bcertificates?\b", "closed plain lacquered box"),
        (r"\bsealed\s+notices?\b", "closed plain wooden notice box"),
        (r"\bnotices?\b", "closed plain wooden notice box"),
        (r"\bdocuments?\b", "closed sealed box"),
        (r"\bpapers?\b", "dark tan cord-tied cloth packet sacks"),
        (r"\borders?\b", "closed sealed order box"),
        (r"\bledgers?\b", "closed ledger box"),
        (r"\bregisters?\b", "closed register box"),
        (r"\bmessages?\b", "closed sealed box"),
        (r"\bpaper\s+face\b", "box face"),
        (r"\bwriting\b", "sealed material"),
    )
    for pattern, repl in replacements:
        safe = re.sub(pattern, repl, safe, flags=re.IGNORECASE)
    return safe


