_FLUX2_KLEIN_JAPANESE_POSITIVE_FORBIDDEN_RE = re.compile(
    r"\b(?:no|zero|text|letters?|caption|title|sign|signboard|label|logo|"
    r"document|paper|scroll|calligraphy|writing|written|kanji|kana|glyph|"
    r"map|wires?|cables?|poles?|utility|telephone|telegraph|crossbar|crossarm|"
    r"electric|switch|outlet|placard|plaque|"
    r"dispatch(?:es)?|orders?)\b",
    re.IGNORECASE,
)


def _sanitize_flux2_klein_japanese_positive_final(prompt: str) -> str:
    """Keep FLUX.2 Japanese positive prompts focused on visible desired material."""
    sentences = re.split(r"(?<=[.!?])\s+", str(prompt or "").strip())
    kept = [
        sentence.strip()
        for sentence in sentences
        if sentence.strip()
        and not _FLUX2_KLEIN_JAPANESE_POSITIVE_FORBIDDEN_RE.search(sentence)
    ]
    return re.sub(r"\s+", " ", " ".join(kept)).strip(" ;,.")


def _flux2_klein_egypt_relevant_scene_text(prompt: str) -> str:
    return " ".join(
        bit
        for bit in (
            _flux2_klein_clean_text(_local_prompt_field(prompt, "Year/period")),
            _flux2_klein_clean_text(_local_prompt_field(prompt, "Exact place")),
            _flux2_klein_clean_text(_local_prompt_field(prompt, "Main subject")),
            _flux2_klein_clean_text(_local_prompt_field(prompt, "Scene")),
            _flux2_klein_clean_text(prompt if not _local_prompt_field(prompt, "Scene") else ""),
        )
        if bit
    )


