def _flux2_klein_egypt_direct_prompt(scene_text: str, compact: str) -> str:
    scene_scan = scene_text or ""
    scan = f"{scene_scan} {compact or ''}"
    decision_scan = scene_scan.strip() or scan
    if not scan.strip():
        return ""
    if re.search(r"\b(?:wall\s+painting|plaster|pigment)\b", scene_scan, re.IGNORECASE) and re.search(
        r"\b(?:hippo|hippopotamus|river\s+monster)\b",
        scene_scan,
        re.IGNORECASE,
    ):
        return _flux2_klein_egypt_direct_plaster_prompt()
    if re.search(
        r"\b(?:hippo|hippopotamus|river\s+monster|jaws|maw|snapping|erupting\s+from\s+water)\b",
        decision_scan,
        re.IGNORECASE,
    ):
        return _flux2_klein_egypt_direct_river_animal_prompt()
    if re.search(r"\b(?:bull|sacred\s+bull)\b", decision_scan, re.IGNORECASE):
        return _flux2_klein_egypt_direct_bull_prompt()
    if re.search(r"\bowl\b|\bowls?\b", decision_scan, re.IGNORECASE):
        return _flux2_klein_egypt_direct_owl_prompt()
    if re.search(r"\blion\b", decision_scan, re.IGNORECASE):
        return _flux2_klein_egypt_direct_lion_prompt()
    if re.search(
        r"\b(?:scribe|scribes|papyrus|write|writes|writing|written|sentence|"
        r"record|records|scroll|scrolling|listing|credits?|creators?|book|"
        r"page|tablet|archive|library|document|Manetho|map|plan|cartouche|"
        r"cartouches|royal\s+names?|carved\s+names?|hieroglyphs?|glyphs?|"
        r"inscription|inscriptions|relief|reliefs|carved|carving|sandstone\s+wall|"
        r"weathered\s+wall|visual[-\s]*surface|symbol\s+of\s+unity|magical\s+symbol|"
        r"crowns\s+merging|glowing\s+.*symbol)\b",
        decision_scan,
        re.IGNORECASE,
    ):
        return _flux2_klein_egypt_direct_workbench_prompt()
    if re.search(
        r"\b(?:modern|globe|armillary|hourglass|safe|vault|bottle|button|clock|"
        r"electric|wire|cable|switch|outlet|red\s+brick|suit|virus|atom\s+symbol|"
        r"pyramid|pyramids|Sphinx|obelisk|Greek\s+column|New\s+Kingdom\s+temple)\b",
        decision_scan,
        re.IGNORECASE,
    ):
        return _flux2_klein_egypt_direct_landscape_prompt()
    if re.search(r"\b(?:armies|army|soldiers?|battle|clashing|weapons?|warriors?)\b", decision_scan, re.IGNORECASE):
        return _flux2_klein_egypt_direct_battle_prompt()
    if re.search(r"\b(?:market|marketplace|grain|fish|citizens|stall|stalls)\b", decision_scan, re.IGNORECASE):
        return _flux2_klein_egypt_direct_market_prompt()
    if re.search(
        r"\b(?:pharaoh|king|Menes|Narmer|ruler|crown|crowns|crook|flail|mask|regalia|"
        r"golden|jewelry|collar|army|soldier|battle|armor|scimitar|sword|khopesh|"
        r"halberd|polearm|temple|statue)\b",
        decision_scan,
        re.IGNORECASE,
    ):
        return _flux2_klein_egypt_direct_ruler_prompt()
    return _flux2_klein_egypt_direct_landscape_prompt()


def _flux2_klein_is_jack_daniel_context(prompt: str) -> bool:
    text = " ".join(
        bit
        for bit in (
            _local_prompt_field(prompt, "Year/period"),
            _local_prompt_field(prompt, "Exact place"),
            _local_prompt_field(prompt, "Scene evidence"),
            _local_prompt_field(prompt, "Main subject"),
            _local_prompt_field(prompt, "Scene"),
            prompt or "",
        )
        if bit
    )
    return bool(
        re.search(r"\b(?:Jack\s+Daniel|Lynchburg|Tennessee|whiskey|whisky|distillery)\b", text, re.IGNORECASE)
        and re.search(r"\b(?:1911|1900s?|early\s+20th\s+century|Tennessee|Lynchburg|Jack\s+Daniel)\b", text, re.IGNORECASE)
    )


