def _flux2_klein_is_valentinian_crisis_scene(prompt: str) -> bool:
    if not _flux2_klein_is_late_roman_valentinian_context(prompt):
        return False
    scene_text = " ".join(
        part
        for part in (
            _local_prompt_field(prompt, "Main subject"),
            _local_scene_excerpt(prompt, limit=700),
        )
        if part
    )
    if re.search(
        r"\b(?:preparing\s+to\s+receive|arrange\s+a\s+bare\s+chair|arranges?\s+a\s+bare\s+chair)\b",
        scene_text,
        re.IGNORECASE,
    ):
        return False
    return bool(
        re.search(
            r"\b(?:collapse|collapses|collapsed|physical\s+failure|medical\s+emergency|"
            r"chair\s+arm|crushes|crushed|stagger|staggers|buckles|fallen|bare\s+chair|"
            r"(?:imperial\s+)?chair\s+stands\s+exposed|"
            r"toppled\s+footstool|emptying\s+imperial\s+seat|empty\s+imperial\s+(?:chair|seat)|"
            r"face\s+strains|jaw\s+locks|shoulders\s+surge|sudden\s+break|attendants?\s+rush|"
            r"attendants?\s+lunge|envoys?\s+recoil|envoys?\s+stagger|accusing\s+arm|"
            r"dropped\s+cloak|curtained\s+cot)\b",
            scene_text,
            re.IGNORECASE,
        )
    )


