    def _flux2_klein_is_sui_goguryeo_open_river_scene(prompt: str) -> bool:
        text = prompt or ""
        if re.search(r"\b645\s*(?:AD|CE|year)?\b", text, re.IGNORECASE):
            return False
        if not re.search(
            r"\b(?:612|Sui|Yangdi|Emperor\s+Yang|Yang\s+of\s+Sui|Liaodong|"
            r"Liao\s+River|Yodong|Eulji|Mundeok|Pyongyang|Yuwen\s+Shu|Yu\s+Zhongwen|"
            r"Goguryeo-Sui)\b|수\s*양제|수나라|요동성|요하|을지|문덕|평양|우문술|우중문|살수",
            text,
            re.IGNORECASE,
        ):
            return False
        scene_field = _local_prompt_field(text, "Scene")
        scene_parts = [
            part
            for part in (
                scene_field,
                _local_prompt_field(text, "Main subject"),
                _local_prompt_field(text, "Scene evidence"),
            )
            if part
        ]
        if not scene_parts:
            scene_parts = [_local_scene_excerpt(text, limit=1600)]
        scene = " ".join(
            part
            for part in scene_parts
            if part
        )
        scene = re.sub(r"\benemy\s+wave\b", "enemy formation", scene, flags=re.IGNORECASE)
        return bool(
            re.search(
                r"\b(?:Salsu|river|riverbank|river\s+bank|river\s+valley|middle\s+of\s+the\s+river|"
                r"northern\s+bank|flood|floodwater|wave|dam|water\s+pressure|lake|crossing|"
                r"Eulji|Mundeok|five[-\s]+word\s+poem|tactical\s+genius|retreat|withdraw|"
                r"survivors?|staggering|swept\s+away|swallowed|carriage|cart\s+stuck)\b|"
                r"살수|강물|강가|강둑|도하|홍수|댐|둑|물살|을지|문덕|오언시|퇴각|쓸려|수몰|진흙탕",
                scene,
                re.IGNORECASE,
            )
        )
    
    
    def _flux2_klein_sui_goguryeo_open_river_prompt(prompt: str) -> str:
        _year, _place, _culture, _subject, scene = _flux2_klein_context(prompt)
        scene_field = _local_prompt_field(prompt, "Scene") or scene
        scene_parts = [
            part
            for part in (
                scene_field,
                _local_prompt_field(prompt, "Main subject"),
                _local_prompt_field(prompt, "Scene evidence"),
            )
            if part
        ]
        if not scene_parts:
            scene_parts = [_local_scene_excerpt(prompt, limit=1600)]
        scene_scan = " ".join(
            part
            for part in scene_parts
            if part
        )
        scene_scan = re.sub(r"\benemy\s+wave\b", "enemy formation", scene_scan, flags=re.IGNORECASE)
        full_scan = f"{prompt} {scene_scan}"
        style = _flux2_klein_style_clause()
        river_place = (
            "the Salsu River crossing"
            if re.search(r"\bSalsu\b|살수", full_scan, re.IGNORECASE)
            else "a muddy river crossing"
        )
        context = (
            f"612 CE Goguryeo-Sui open river battlefield at {river_place}. "
            "Visible era and place come first: cold river water, mud banks, low hills, "
            "wet reeds, plain iron weapons, lamellar armor, hemp garments, rope harness, "
            "rough wood, leather, stone, and open sky."
        )
        composition = (
            "Composition: one continuous 16:9 outdoor frame, horizon low enough to show "
            "river surface, banks, sky, and distant hills, with the current action placed "
            "in the center foreground."
        )
        if re.search(
            r"\b(?:Emperor\s+Yang\s+of\s+Sui|Sui\s+Yangdi|Yangdi)\b.*\b(?:animal[-\s]+drawn|command\s+cart|spoked\s+wooden\s+wheels|rope\s+harness|cart\s+stuck)\b|"
            r"\b(?:animal[-\s]+drawn|command\s+cart|spoked\s+wooden\s+wheels|rope\s+harness|cart\s+stuck)\b.*\b(?:Emperor\s+Yang\s+of\s+Sui|Sui\s+Yangdi|Yangdi)\b",
            full_scan,
            re.IGNORECASE,
        ):
            action = (
                "Scene subject: Emperor Yang of Sui withdrawing beside an animal-drawn open "
                "wooden command cart. Visible action: the cart sits trapped in deep open mud "
                "near the riverbank while exhausted guards pull rope harnesses and the emperor "
                "turns back in visible panic. Visible inventory: spoked wooden wheels, rough "
                "axle, horse tack, mud, cold haze, broken spear shafts, plain lamellar guards, "
                "and distant low hills. No soldiers-only swamp crawl."
            )
        elif re.search(r"\b(?:five[-\s]+word\s+poem|poem|tactical\s+genius|Eulji|Mundeok)\b|오언시|을지|문덕", scene_scan, re.IGNORECASE):
            action = (
                "Scene subject: Eulji Mundeok at an outdoor command mat on the riverbank. "
                "Visible action: he studies closed cord-tied bamboo slip packets while officers "
                "watch the river crossing. Visible inventory: closed cord-tied bamboo slip "
                "bundles only, unwritten tan bamboo rods with visible bamboo grain, brush set "
                "aside, cord knots, plain uninterrupted robes and belts, mud, cold water, plain "
                "spears, wet reeds, and low hills."
            )
        elif re.search(r"\b(?:carriage|cart\s+stuck|retreat|withdraws?|withdrawing)\b|퇴각|진흙탕", scene_scan, re.IGNORECASE):
            action = (
                "Scene subject: Emperor Yang of Sui withdrawing beside an animal-drawn open "
                "wooden command cart. Visible action: the cart sits trapped in deep open mud "
                "near the riverbank while exhausted guards pull rope harnesses. Visible inventory: "
                "spoked wooden wheels, rough axle, horse tack, mud, cold haze, broken spear shafts, "
                "and distant low hills."
            )
        elif re.search(r"\b(?:dam|water\s+pressure|lake)\b|댐|둑", scene_scan, re.IGNORECASE):
            action = (
                "Scene subject: rough earth-and-log temporary river dam. Visible action: heavy "
                "water pressure bulges through leaking mud seams. Visible inventory: logs, packed "
                "earth, branches, cold lake water, muddy banks, spray, reeds, open sky, and low hills."
            )
        elif re.search(r"\b(?:wave|flood|floodwater|swept|swallowed|dark\s+red)\b|홍수|물살|쓸려|수몰", scene_scan, re.IGNORECASE):
            action = (
                "Scene subject: dark floodwater in the open river valley. Visible action: the "
                "surge carries broken shields, spear shafts, torn lamellar plates, and exhausted "
                "Sui soldiers through muddy water. Visible inventory: river spray, wet reeds, mud, "
                "plain armor, open sky, and low hills."
            )
        elif re.search(r"\b(?:word|stone\s+monument|carved|Salsu)\b|살수", scene_scan, re.IGNORECASE):
            action = (
                "Scene subject: unmarked blood-stained river stone on the muddy bank. Visible "
                "action: cold water eddies around the stone and broken spear shafts. Visible "
                "inventory: torn armor plates, wet reeds, mud, stone cracks, open sky, and low hills."
            )
        else:
            action = (
                "Scene subject: exhausted Sui soldiers at a cold open river crossing. Visible "
                "action: soldiers struggle in the water while Goguryeo infantry hold plain spears "
                "on the muddy banks. Visible inventory: broken shields, water spray, wet reeds, "
                "lamellar armor, mud, open sky, and low hills."
            )
        return re.sub(r"\s+", " ", f"{context} {action} {composition} {style}").strip(" ;,.")
    
    
