        for pattern, replacement in replacements:
            value = re.sub(pattern, replacement, value, flags=re.IGNORECASE)
        if tang_645_context:
            value = re.sub(r"\bnortheastern\s+frontier\s+fortress\s+area\b", "Liaodong Fortress", value, flags=re.IGNORECASE)
