    def _append_unique(target: list[str], sentence: str) -> None:
        sentence = _md_visible_sentence(sentence)
        if not sentence or not _safe_positive_sentence(sentence):
            return
        key = sentence.lower()
        if all(existing.lower() != key for existing in target):
            target.append(sentence)

    def _insert_unique(target: list[str], index: int, sentence: str) -> None:
        sentence = _md_visible_sentence(sentence)
        if not sentence or not _safe_positive_sentence(sentence):
            return
        key = sentence.lower()
        if all(existing.lower() != key for existing in target):
            target.insert(max(0, min(index, len(target))), sentence)

    def _global_field(label: str) -> str:
        match = re.search(rf"{re.escape(label)}:\s*([^;]+)", source, re.IGNORECASE)
        return _flux2_klein_clean_text(match.group(1)) if match else ""

    def _strip_negated_imjin_context_terms(value: str) -> str:
        out = str(value or "")
        imjin_terms = (
            r"1592|1593|1594|1595|1596|1597|1598|Toyotomi|Hideyoshi|Joseon|Seonjo|"
            r"Hanseong|Hizen|Nagoya|Imjin|Ming|samurai|daimyo|豊臣|秀吉|宣祖|"
            r"朝鮮|壬辰|임진|선조|히데요시"
        )
        out = re.sub(
            rf"\b(?:not|no|never|avoid|without|exclude|excluding|zero)\b[^.;|]*?(?:{imjin_terms})[^.;|]*",
            "",
            out,
            flags=re.IGNORECASE,
        )
        return out

    def _imjin_source_field_scan() -> str:
        fields = (
            _local_prompt_field(source, "Year/period"),
            _local_prompt_field(source, "Exact place"),
            _local_prompt_field(source, "Place scope"),
            _local_prompt_field(source, "Culture scope"),
            _local_prompt_field(source, "Main subject"),
            _local_prompt_field(source, "Scene"),
            _local_prompt_field(source, "Scene evidence"),
            _global_field("Time range"),
            _global_field("Place scope"),
            _global_field("Culture scope"),
        )
        return _strip_negated_imjin_context_terms(" ".join(bit for bit in fields if bit))

    def _is_imjin_context() -> bool:
        scan = " ".join(
            bit
            for bit in (
                _imjin_source_field_scan(),
                _local_prompt_field(source, "Main subject"),
                _local_prompt_field(source, "Scene"),
                _local_prompt_field(source, "Scene evidence"),
            )
            if bit
        )
        return bool(
            re.search(
                r"\b(?:1592|1593|1594|1595|1596|1597|1598|Toyotomi|Hideyoshi|Joseon|Seonjo|Hanseong|Hizen|Nagoya|Imjin|Ming|samurai|daimyo)\b|"
                r"(?:豊臣|秀吉|宣祖|朝鮮|壬辰|임진|선조|히데요시)",
                scan,
                re.IGNORECASE,
            )
        )

    def _is_siam_boat_context() -> bool:
        siam_scan = f"{source} {text} {_md_local_scan()}"
        local_scene_scan = " ".join(
            bit
            for bit in (
                _local_prompt_field(source, "Exact place"),
                _local_prompt_field(source, "Main subject"),
                _local_prompt_field(source, "Scene"),
                _local_prompt_field(source, "Scene evidence"),
            )
            if bit
        )
        return bool(
            re.search(
                r"\b(?:siam|siamese|sunanda|kumariratana|chulalongkorn|chakri|chao\s+phraya|bangkok|bang\s+pa-in|royal\s+court)\b",
                siam_scan,
                re.IGNORECASE,
            )
            and re.search(
                r"\b(?:boat|boats|boatmen|hull|pier|craft|vessel|prow|oars?|paddle|royal\s+travel)\b",
                local_scene_scan,
                re.IGNORECASE,
            )
        )

