    def _md_source_scene_is_animal_only() -> bool:
        local_scene_scan = " ".join(
            bit
            for bit in (
                _local_prompt_field(source, "Main subject"),
                _local_prompt_field(source, "Scene"),
                _local_prompt_field(source, "Scene evidence"),
            )
            if bit
        )
        if _LOCAL_ANIMAL_DRAWN_VEHICLE_SCENE_RE.search(local_scene_scan):
            return False
        return bool(
            local_scene_scan
            and _LOCAL_ANIMAL_FOCUS_SCENE_RE.search(local_scene_scan)
            and not _LOCAL_EXPLICIT_HUMAN_OR_COMBATANT_SCENE_RE.search(local_scene_scan)
        )

