def _local_is_early_ne_asian_or_ep13_context(prompt: str) -> bool:
    scan = " ".join(
        bit
        for bit in (
            _local_prompt_field(prompt, "Year/period"),
            _local_prompt_field(prompt, "Exact place"),
            _local_prompt_field(prompt, "Scene evidence"),
            _local_scene_excerpt(prompt),
            prompt or "",
        )
        if bit
    )
    return bool(
        _local_is_early_goguryeo_context(prompt)
        or re.search(
            r"\b(?:400\s*[~\-]\s*415|399|400|401|402|403|404|405|406|407|408|409|410|411|412|413|414|415)\b|"
            r"\b(?:Silla|Goguryeo|Jongbalseong|Houchong)\b|신라|고구려|종발성|호우총|호우명",
            scan,
            re.IGNORECASE,
        )
    )


