def _local_scene_identity_hint_phrase(prompt: str) -> str:
    scene = _local_scene_excerpt(prompt)
    facts: list[str] = []
    for pattern, fact in _LOCAL_KNOWN_SCENE_IDENTITY_FACTS:
        if pattern.search(scene):
            facts.append(fact)
    if not facts:
        return ""
    return "Confirmed identity facts from the Scene: " + "; ".join(dict.fromkeys(facts)) + "."


def _local_closeup_scene_excerpt(prompt: str) -> str:
    text = _local_scene_excerpt(prompt)
    replacements = (
        (r"\bafter\s+escape\b", "under pressure"),
        (r"\bafter\s+battle\b", "under pressure"),
        (r"\bwounded\b", "tense"),
        (r"\bbloodied\b", "tense"),
        (r"\bscarred\b", "tense"),
        (r"\binjured\b", "tense"),
        (r"\bbruised\b", "tense"),
        (r"상처[가-힣]*", "긴장한"),
        (r"피투성이", "긴장한"),
        (r"부상[가-힣]*", "긴장한"),
    )
    for pattern, replacement in replacements:
        text = re.sub(pattern, replacement, text, flags=re.IGNORECASE)
    text = re.sub(r"\s{2,}", " ", text).strip(" ;,")
    return text or "one historical person from the scene"


